const CONJ_THEORY_HTML = "\n<div class=\"glass rounded-2xl p-4 mb-4\" style=\"border-left:4px solid var(--accent)\">\n  <div class=\"font-800 text-dark2 mb-2\">🌟 TỔNG QUAN — Liên từ trong tiếng Anh (Conjunctions)</div>\n  <div class=\"text-sm text-soft\">Liên từ là từ dùng để liên kết hai từ, cụm từ, mệnh đề hoặc câu lại với nhau. Liên từ được chia thành 3 nhóm chính: liên từ kết hợp, liên từ tương quan và liên từ phụ thuộc.</div>\n  <div class=\"ex-card mt-2\">She is tired <b>but</b> happy. <span style=\"color:var(--accent);font-size:13px\">→ Cô ấy mệt nhưng vui.</span></div>\n  <div class=\"ex-card mt-2\"><b>Although</b> it was raining, we went out. <span style=\"color:var(--accent);font-size:13px\">→ Mặc dù trời mưa, chúng tôi vẫn ra ngoài.</span></div>\n</div>\n\n<details open class=\"mb-3\">\n  <summary class=\"glass rounded-2xl p-4 font-700 text-dark2 flex items-center gap-2 cursor-pointer card-hover\">\n    <span style=\"background:linear-gradient(90deg,#457B9D,#5b9bc4);color:#fff;padding:2px 10px;border-radius:8px;font-size:12px\">1</span> Liên từ kết hợp (Coordinating Conjunctions)\n    <i data-lucide=\"chevron-down\" style=\"width:16px;height:16px;margin-left:auto;color:var(--accent)\"></i>\n  </summary>\n  <div class=\"mt-2 glass rounded-2xl p-4\">\n    <div class=\"text-sm text-soft mb-2\">Dùng để nối các từ loại, cụm từ hoặc mệnh đề NGANG HÀNG nhau (tính từ với tính từ, danh từ với danh từ, mệnh đề độc lập với mệnh đề độc lập). Ghi nhớ bằng <b>FANBOYS</b>: For - And - Nor - But - Or - Yet - So.</div>\n    <table style=\"width:100%;border-collapse:collapse;font-size:13px\" class=\"mt-2\">\n      <tbody>\n        <tr><td style=\"padding:6px;width:15%\"><span class=\"suffix-pill\">for</span></td><td style=\"padding:6px;color:var(--text-soft)\">vì (trang trọng)</td></tr>\n        <tr><td style=\"padding:6px\"><span class=\"suffix-pill\">and</span></td><td style=\"padding:6px;color:var(--text-soft)\">và</td></tr>\n        <tr><td style=\"padding:6px\"><span class=\"suffix-pill\">nor</span></td><td style=\"padding:6px;color:var(--text-soft)\">cũng không</td></tr>\n        <tr><td style=\"padding:6px\"><span class=\"suffix-pill\">but</span></td><td style=\"padding:6px;color:var(--text-soft)\">nhưng</td></tr>\n        <tr><td style=\"padding:6px\"><span class=\"suffix-pill\">or</span></td><td style=\"padding:6px;color:var(--text-soft)\">hoặc là</td></tr>\n        <tr><td style=\"padding:6px\"><span class=\"suffix-pill\">yet</span></td><td style=\"padding:6px;color:var(--text-soft)\">vậy mà, thế mà</td></tr>\n        <tr><td style=\"padding:6px\"><span class=\"suffix-pill\">so</span></td><td style=\"padding:6px;color:var(--text-soft)\">vì vậy</td></tr>\n      </tbody>\n    </table>\n    <div class=\"mt-3 p-3 rounded-xl\" style=\"background:#fff3cd;border-left:3px solid #ffc107;font-size:13px\">⚠️ Khi nối 2 mệnh đề độc lập bằng liên từ kết hợp, thường có dấu phẩy đứng trước liên từ: <i>I was tired, so I went to bed.</i></div>\n  </div>\n</details>\n\n<details class=\"mb-3\">\n  <summary class=\"glass rounded-2xl p-4 font-700 text-dark2 flex items-center gap-2 cursor-pointer card-hover\">\n    <span style=\"background:linear-gradient(90deg,#9b5de5,#c39bf0);color:#fff;padding:2px 10px;border-radius:8px;font-size:12px\">2</span> Liên từ tương quan (Correlative Conjunctions)\n    <i data-lucide=\"chevron-down\" style=\"width:16px;height:16px;margin-left:auto;color:var(--accent)\"></i>\n  </summary>\n  <div class=\"mt-2 glass rounded-2xl p-4\" style=\"overflow-x:auto\">\n    <div class=\"text-sm text-soft mb-2\">Đi theo CẶP, liên kết 2 thành phần có chức năng ngữ pháp tương đương nhau.</div>\n    <table style=\"width:100%;border-collapse:collapse;font-size:13px;min-width:520px\">\n      <thead><tr style=\"background:rgba(69,123,157,.1)\"><th style=\"padding:8px;text-align:left\">Cặp liên từ</th><th style=\"padding:8px;text-align:left\">Nghĩa</th></tr></thead>\n      <tbody>\n        <tr><td style=\"padding:8px\"><b>both . . . and</b></td><td style=\"padding:8px;color:var(--text-soft)\">vừa... vừa..., cả... và...</td></tr>\n        <tr><td style=\"padding:8px\"><b>not only . . . but also</b></td><td style=\"padding:8px;color:var(--text-soft)\">không những... mà còn...</td></tr>\n        <tr><td style=\"padding:8px\"><b>either . . . or</b></td><td style=\"padding:8px;color:var(--text-soft)\">hoặc... hoặc...</td></tr>\n        <tr><td style=\"padding:8px\"><b>neither . . . nor</b></td><td style=\"padding:8px;color:var(--text-soft)\">không... cũng không...</td></tr>\n        <tr><td style=\"padding:8px\"><b>whether . . . or</b></td><td style=\"padding:8px;color:var(--text-soft)\">dù... hay...</td></tr>\n        <tr><td style=\"padding:8px\"><b>as/so . . . as</b></td><td style=\"padding:8px;color:var(--text-soft)\">như là, bằng/không bằng</td></tr>\n        <tr><td style=\"padding:8px\"><b>no sooner...than</b></td><td style=\"padding:8px;color:var(--text-soft)\">vừa mới... thì đã... (đảo ngữ)</td></tr>\n        <tr><td style=\"padding:8px\"><b>hardly/scarcely/barely...when</b></td><td style=\"padding:8px;color:var(--text-soft)\">vừa mới... thì đã... (đảo ngữ)</td></tr>\n        <tr><td style=\"padding:8px\"><b>so + adj/adv...that</b></td><td style=\"padding:8px;color:var(--text-soft)\">đến mức... đến nỗi</td></tr>\n        <tr><td style=\"padding:8px\"><b>such + (a/an) + adj + N...that</b></td><td style=\"padding:8px;color:var(--text-soft)\">đến mức... đến nỗi</td></tr>\n      </tbody>\n    </table>\n    <div class=\"mt-3 p-3 rounded-xl\" style=\"background:#d4edda;border-left:3px solid #2ecc71;font-size:13px\">✅ Với NO SOONER/HARDLY/SCARCELY đứng đầu câu, phải ĐẢO NGỮ: <i>No sooner had he arrived than the meeting started.</i></div>\n  </div>\n</details>\n\n<details class=\"mb-3\">\n  <summary class=\"glass rounded-2xl p-4 font-700 text-dark2 flex items-center gap-2 cursor-pointer card-hover\">\n    <span style=\"background:linear-gradient(90deg,#e63946,#ff8fa3);color:#fff;padding:2px 10px;border-radius:8px;font-size:12px\">3</span> Liên từ phụ thuộc (Subordinating Conjunctions)\n    <i data-lucide=\"chevron-down\" style=\"width:16px;height:16px;margin-left:auto;color:var(--accent)\"></i>\n  </summary>\n  <div class=\"mt-2 glass rounded-2xl p-4\" style=\"overflow-x:auto\">\n    <div class=\"text-sm text-soft mb-3\">Nối mệnh đề PHỤ với mệnh đề CHÍNH. Được nhóm theo chức năng dưới đây.</div>\n\n    <div class=\"font-700 text-dark2 mb-2\">3.1 Chỉ thời gian</div>\n    <table style=\"width:100%;border-collapse:collapse;font-size:13px;min-width:480px\">\n      <tbody>\n        <tr><td style=\"padding:6px;width:35%\"><span class=\"suffix-pill\">after</span></td><td style=\"padding:6px;color:var(--text-soft)\">sau khi</td></tr>\n        <tr><td style=\"padding:6px\"><span class=\"suffix-pill\">before</span></td><td style=\"padding:6px;color:var(--text-soft)\">trước khi</td></tr>\n        <tr><td style=\"padding:6px\"><span class=\"suffix-pill\">as/when</span></td><td style=\"padding:6px;color:var(--text-soft)\">khi</td></tr>\n        <tr><td style=\"padding:6px\"><span class=\"suffix-pill\">as soon as</span></td><td style=\"padding:6px;color:var(--text-soft)\">ngay khi</td></tr>\n        <tr><td style=\"padding:6px\"><span class=\"suffix-pill\">just as</span></td><td style=\"padding:6px;color:var(--text-soft)\">vừa lúc</td></tr>\n        <tr><td style=\"padding:6px\"><span class=\"suffix-pill\">once</span></td><td style=\"padding:6px;color:var(--text-soft)\">một khi</td></tr>\n        <tr><td style=\"padding:6px\"><span class=\"suffix-pill\">since</span></td><td style=\"padding:6px;color:var(--text-soft)\">từ khi</td></tr>\n        <tr><td style=\"padding:6px\"><span class=\"suffix-pill\">until/till</span></td><td style=\"padding:6px;color:var(--text-soft)\">cho đến khi</td></tr>\n        <tr><td style=\"padding:6px\"><span class=\"suffix-pill\">while</span></td><td style=\"padding:6px;color:var(--text-soft)\">trong khi</td></tr>\n      </tbody>\n    </table>\n\n    <div class=\"font-700 text-dark2 mb-2 mt-4\">3.2 Chỉ nguyên nhân</div>\n    <table style=\"width:100%;border-collapse:collapse;font-size:13px;min-width:480px\">\n      <tbody>\n        <tr><td style=\"padding:6px;width:35%\"><span class=\"suffix-pill\">because/since/as</span></td><td style=\"padding:6px;color:var(--text-soft)\">vì (+ mệnh đề S+V)</td></tr>\n        <tr><td style=\"padding:6px\"><span class=\"suffix-pill\">now that</span></td><td style=\"padding:6px;color:var(--text-soft)\">vì giờ đây</td></tr>\n        <tr><td style=\"padding:6px\"><span class=\"suffix-pill\">seeing that</span></td><td style=\"padding:6px;color:var(--text-soft)\">vì, xét thấy</td></tr>\n        <tr><td style=\"padding:6px\"><span class=\"suffix-pill\">because of/due to/owing to/on account of</span></td><td style=\"padding:6px;color:var(--text-soft)\">vì (+ danh từ/cụm danh từ — GIỚI TỪ)</td></tr>\n        <tr><td style=\"padding:6px\"><span class=\"suffix-pill\">thanks to</span></td><td style=\"padding:6px;color:var(--text-soft)\">nhờ có (+ danh từ, nghĩa tích cực)</td></tr>\n      </tbody>\n    </table>\n    <div class=\"mt-2 p-3 rounded-xl\" style=\"background:#fff3cd;border-left:3px solid #ffc107;font-size:13px\">⚠️ Phân biệt: BECAUSE + mệnh đề (S+V) >< BECAUSE OF/DUE TO/OWING TO + danh từ (không có động từ chia).</div>\n\n    <div class=\"font-700 text-dark2 mb-2 mt-4\">3.3 Chỉ mục đích</div>\n    <table style=\"width:100%;border-collapse:collapse;font-size:13px;min-width:480px\">\n      <tbody>\n        <tr><td style=\"padding:6px;width:35%\"><span class=\"suffix-pill\">so that/in order that</span></td><td style=\"padding:6px;color:var(--text-soft)\">để mà (+ mệnh đề, thường có modal verb)</td></tr>\n        <tr><td style=\"padding:6px\"><span class=\"suffix-pill\">in order to/so as to</span></td><td style=\"padding:6px;color:var(--text-soft)\">để (+ động từ nguyên mẫu)</td></tr>\n        <tr><td style=\"padding:6px\"><span class=\"suffix-pill\">for fear that/lest</span></td><td style=\"padding:6px;color:var(--text-soft)\">vì e rằng, vì sợ rằng</td></tr>\n      </tbody>\n    </table>\n\n    <div class=\"font-700 text-dark2 mb-2 mt-4\">3.4 Chỉ kết quả</div>\n    <table style=\"width:100%;border-collapse:collapse;font-size:13px;min-width:480px\">\n      <tbody>\n        <tr><td style=\"padding:6px;width:35%\"><span class=\"suffix-pill\">so</span></td><td style=\"padding:6px;color:var(--text-soft)\">vì vậy (liên từ kết hợp, có dấu phẩy trước)</td></tr>\n        <tr><td style=\"padding:6px\"><span class=\"suffix-pill\">therefore/thus/hence/consequently</span></td><td style=\"padding:6px;color:var(--text-soft)\">do đó, do vậy (trạng từ nối câu)</td></tr>\n        <tr><td style=\"padding:6px\"><span class=\"suffix-pill\">as a result/as a consequence</span></td><td style=\"padding:6px;color:var(--text-soft)\">kết quả là, hậu quả là</td></tr>\n      </tbody>\n    </table>\n\n    <div class=\"font-700 text-dark2 mb-2 mt-4\">3.5 Chỉ sự nhượng bộ / tương phản</div>\n    <table style=\"width:100%;border-collapse:collapse;font-size:13px;min-width:480px\">\n      <tbody>\n        <tr><td style=\"padding:6px;width:35%\"><span class=\"suffix-pill\">although/though/even though</span></td><td style=\"padding:6px;color:var(--text-soft)\">mặc dù (+ mệnh đề S+V)</td></tr>\n        <tr><td style=\"padding:6px\"><span class=\"suffix-pill\">despite/in spite of</span></td><td style=\"padding:6px;color:var(--text-soft)\">mặc dù, bất chấp (+ danh từ/V-ing — GIỚI TỪ)</td></tr>\n        <tr><td style=\"padding:6px\"><span class=\"suffix-pill\">while/whereas</span></td><td style=\"padding:6px;color:var(--text-soft)\">trong khi (đó) — chỉ sự đối lập giữa 2 mệnh đề</td></tr>\n        <tr><td style=\"padding:6px\"><span class=\"suffix-pill\">however/nevertheless/nonetheless</span></td><td style=\"padding:6px;color:var(--text-soft)\">tuy nhiên (trạng từ nối câu)</td></tr>\n        <tr><td style=\"padding:6px\"><span class=\"suffix-pill\">on the other hand/in contrast/by contrast</span></td><td style=\"padding:6px;color:var(--text-soft)\">mặt khác, trái lại</td></tr>\n        <tr><td style=\"padding:6px\"><span class=\"suffix-pill\">on the contrary</span></td><td style=\"padding:6px;color:var(--text-soft)\">trái lại (phủ nhận điều vừa nói)</td></tr>\n      </tbody>\n    </table>\n    <div class=\"mt-2 p-3 rounded-xl\" style=\"background:#fff3cd;border-left:3px solid #ffc107;font-size:13px\">⚠️ Phân biệt: ALTHOUGH/THOUGH/EVEN THOUGH + mệnh đề (S+V) >< DESPITE/IN SPITE OF + danh từ/V-ing (không có động từ chia).</div>\n\n    <div class=\"font-700 text-dark2 mb-2 mt-4\">3.6 Chỉ điều kiện</div>\n    <table style=\"width:100%;border-collapse:collapse;font-size:13px;min-width:480px\">\n      <tbody>\n        <tr><td style=\"padding:6px;width:35%\"><span class=\"suffix-pill\">if</span></td><td style=\"padding:6px;color:var(--text-soft)\">nếu</td></tr>\n        <tr><td style=\"padding:6px\"><span class=\"suffix-pill\">unless</span></td><td style=\"padding:6px;color:var(--text-soft)\">trừ khi (= if...not)</td></tr>\n        <tr><td style=\"padding:6px\"><span class=\"suffix-pill\">as long as/so long as/provided that/providing that</span></td><td style=\"padding:6px;color:var(--text-soft)\">miễn là, với điều kiện là</td></tr>\n        <tr><td style=\"padding:6px\"><span class=\"suffix-pill\">in case/in the event that</span></td><td style=\"padding:6px;color:var(--text-soft)\">phòng khi, trong trường hợp</td></tr>\n        <tr><td style=\"padding:6px\"><span class=\"suffix-pill\">suppose/supposing that</span></td><td style=\"padding:6px;color:var(--text-soft)\">giả sử</td></tr>\n        <tr><td style=\"padding:6px\"><span class=\"suffix-pill\">even if</span></td><td style=\"padding:6px;color:var(--text-soft)\">cho dù, ngay cả khi (việc chưa chắc xảy ra)</td></tr>\n        <tr><td style=\"padding:6px\"><span class=\"suffix-pill\">otherwise/or else</span></td><td style=\"padding:6px;color:var(--text-soft)\">nếu không (thì)</td></tr>\n      </tbody>\n    </table>\n\n    <div class=\"font-700 text-dark2 mb-2 mt-4\">3.7 Chỉ cách thức / bổ sung khác</div>\n    <table style=\"width:100%;border-collapse:collapse;font-size:13px;min-width:480px\">\n      <tbody>\n        <tr><td style=\"padding:6px;width:35%\"><span class=\"suffix-pill\">as if/as though</span></td><td style=\"padding:6px;color:var(--text-soft)\">như thể là</td></tr>\n        <tr><td style=\"padding:6px\"><span class=\"suffix-pill\">moreover/besides/furthermore/in addition</span></td><td style=\"padding:6px;color:var(--text-soft)\">ngoài ra, bên cạnh đó, hơn nữa (trạng từ nối câu)</td></tr>\n        <tr><td style=\"padding:6px\"><span class=\"suffix-pill\">in addition to/as well as</span></td><td style=\"padding:6px;color:var(--text-soft)\">ngoài...ra, cũng như (+ danh từ/V-ing — GIỚI TỪ)</td></tr>\n        <tr><td style=\"padding:6px\"><span class=\"suffix-pill\">in other words</span></td><td style=\"padding:6px;color:var(--text-soft)\">nói cách khác</td></tr>\n      </tbody>\n    </table>\n  </div>\n</details>\n";
const CONJ_EX1 = [{"id": "conj_ex1_1", "type": "fill", "q": "He hated being in the army __________ he had to obey commands.", "vi": "", "opts": ["A. because", "B. because of", "C. although", "D. in spite of"], "ans": 0, "explain_detail": "<div class=\"mb-2 p-3 rounded-xl font-700\" style=\"background:#d4edda;color:#155724\">&#9989; Đáp án đúng: A. because</div><div class=\"ex-card mb-3\">He hated being in the army <b>because</b> he had to obey commands.<br><span style=\"color:var(--accent);font-size:13px\">Anh ấy ghét việc ở trong quân đội vì anh phải tuân lệnh.</span></div><div class=\"mb-3 p-3 rounded-xl\" style=\"background:#f8f9fa;border-left:3px solid var(--accent);font-size:13px\">&#128209; <b>Thuộc phần lý thuyết:</b> Liên từ phụ thuộc chỉ NGUYÊN NHÂN (because/because of/due to...)</div><div class=\"mb-2 font-700 text-dark2\" style=\"font-size:13px\">&#128218; Giải thích chi tiết cả 4 đáp án:</div><div class=\"mb-2 p-3 rounded-xl\" style=\"background:#d4edda;border:1px solid rgba(0,0,0,.06)\"><div style=\"font-weight:700;color:#155724\">&#9989; A. because</div><div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\">vì (liên từ + mệnh đề S+V) → đúng, sau chỗ trống là mệnh đề đầy đủ 'he had to obey commands'</div></div><div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\"><div style=\"font-weight:700;color:#555\">&#9642;&#65039; B. because of</div><div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\">vì (giới từ + danh từ/cụm danh từ, KHÔNG đi với mệnh đề đầy đủ) → sai vì sau nó là cả mệnh đề</div></div><div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\"><div style=\"font-weight:700;color:#555\">&#9642;&#65039; C. although</div><div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\">mặc dù (chỉ sự tương phản, không hợp nghĩa nhân-quả ở đây)</div></div><div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\"><div style=\"font-weight:700;color:#555\">&#9642;&#65039; D. in spite of</div><div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\">mặc dù, bất chấp (giới từ, không đi với mệnh đề, cũng sai nghĩa)</div></div>"}, {"id": "conj_ex1_2", "type": "fill", "q": "__________ we've got a few minutes to wait for the train, let's have a cup of coffee.", "vi": "", "opts": ["A. Despite", "B. Even though", "C. Since", "D. Due to"], "ans": 2, "explain_detail": "<div class=\"mb-2 p-3 rounded-xl font-700\" style=\"background:#d4edda;color:#155724\">&#9989; Đáp án đúng: C. Since</div><div class=\"ex-card mb-3\"><b>Since</b> we've got a few minutes to wait for the train, let's have a cup of coffee.<br><span style=\"color:var(--accent);font-size:13px\">Vì chúng ta có vài phút chờ tàu, nên làm một tách cà phê đi.</span></div><div class=\"mb-3 p-3 rounded-xl\" style=\"background:#f8f9fa;border-left:3px solid var(--accent);font-size:13px\">&#128209; <b>Thuộc phần lý thuyết:</b> Liên từ phụ thuộc chỉ NGUYÊN NHÂN (since = vì, mang tính hiển nhiên)</div><div class=\"mb-2 font-700 text-dark2\" style=\"font-size:13px\">&#128218; Giải thích chi tiết cả 4 đáp án:</div><div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\"><div style=\"font-weight:700;color:#555\">&#9642;&#65039; A. Despite</div><div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\">mặc dù (giới từ, sai cả cấu trúc lẫn nghĩa nhân quả)</div></div><div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\"><div style=\"font-weight:700;color:#555\">&#9642;&#65039; B. Even though</div><div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\">mặc dù (chỉ tương phản, không hợp nghĩa nguyên nhân ở đây)</div></div><div class=\"mb-2 p-3 rounded-xl\" style=\"background:#d4edda;border:1px solid rgba(0,0,0,.06)\"><div style=\"font-weight:700;color:#155724\">&#9989; C. Since</div><div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\">vì (liên từ nêu lý do hiển nhiên) → đúng, hợp lý: vì còn thời gian nên uống cà phê</div></div><div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\"><div style=\"font-weight:700;color:#555\">&#9642;&#65039; D. Due to</div><div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\">do, bởi vì (giới từ + danh từ, không đi với mệnh đề đầy đủ)</div></div>"}, {"id": "conj_ex1_3", "type": "fill", "q": "I asked the teacher if I could be excused from football practice __________ my knee still hurt.", "vi": "", "opts": ["A. but", "B. yet", "C. so", "D. as"], "ans": 3, "explain_detail": "<div class=\"mb-2 p-3 rounded-xl font-700\" style=\"background:#d4edda;color:#155724\">&#9989; Đáp án đúng: D. as</div><div class=\"ex-card mb-3\">I asked the teacher if I could be excused from football practice <b>as</b> my knee still hurt.<br><span style=\"color:var(--accent);font-size:13px\">Tôi xin cô giáo cho nghỉ tập bóng đá vì đầu gối tôi vẫn còn đau.</span></div><div class=\"mb-3 p-3 rounded-xl\" style=\"background:#f8f9fa;border-left:3px solid var(--accent);font-size:13px\">&#128209; <b>Thuộc phần lý thuyết:</b> Liên từ phụ thuộc chỉ NGUYÊN NHÂN (as = vì)</div><div class=\"mb-2 font-700 text-dark2\" style=\"font-size:13px\">&#128218; Giải thích chi tiết cả 4 đáp án:</div><div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\"><div style=\"font-weight:700;color:#555\">&#9642;&#65039; A. but</div><div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\">nhưng (liên từ chỉ tương phản, sai nghĩa)</div></div><div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\"><div style=\"font-weight:700;color:#555\">&#9642;&#65039; B. yet</div><div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\">vậy mà (chỉ tương phản, sai nghĩa)</div></div><div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\"><div style=\"font-weight:700;color:#555\">&#9642;&#65039; C. so</div><div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\">vì vậy (chỉ kết quả, không hợp vì vế sau là NGUYÊN NHÂN của việc xin nghỉ)</div></div><div class=\"mb-2 p-3 rounded-xl\" style=\"background:#d4edda;border:1px solid rgba(0,0,0,.06)\"><div style=\"font-weight:700;color:#155724\">&#9989; D. as</div><div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\">vì (liên từ nêu lý do) → đúng, đầu gối đau LÀ LÝ DO xin nghỉ</div></div>"}, {"id": "conj_ex1_4", "type": "fill", "q": "The game has been cancelled __________ unfavorable weather conditions.", "vi": "", "opts": ["A. because", "B. due to", "C. in spite of", "D. although"], "ans": 1, "explain_detail": "<div class=\"mb-2 p-3 rounded-xl font-700\" style=\"background:#d4edda;color:#155724\">&#9989; Đáp án đúng: B. due to</div><div class=\"ex-card mb-3\">The game has been cancelled <b>due to</b> unfavorable weather conditions.<br><span style=\"color:var(--accent);font-size:13px\">Trận đấu đã bị hủy vì điều kiện thời tiết bất lợi.</span></div><div class=\"mb-3 p-3 rounded-xl\" style=\"background:#f8f9fa;border-left:3px solid var(--accent);font-size:13px\">&#128209; <b>Thuộc phần lý thuyết:</b> Giới từ chỉ NGUYÊN NHÂN (due to/because of + danh từ)</div><div class=\"mb-2 font-700 text-dark2\" style=\"font-size:13px\">&#128218; Giải thích chi tiết cả 4 đáp án:</div><div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\"><div style=\"font-weight:700;color:#555\">&#9642;&#65039; A. because</div><div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\">vì (liên từ + mệnh đề, nhưng sau chỗ trống chỉ là cụm danh từ 'unfavorable weather conditions') → sai cấu trúc</div></div><div class=\"mb-2 p-3 rounded-xl\" style=\"background:#d4edda;border:1px solid rgba(0,0,0,.06)\"><div style=\"font-weight:700;color:#155724\">&#9989; B. due to</div><div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\">do, bởi vì (giới từ + danh từ) → đúng, phù hợp với cụm danh từ phía sau</div></div><div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\"><div style=\"font-weight:700;color:#555\">&#9642;&#65039; C. in spite of</div><div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\">mặc dù, bất chấp (sai nghĩa nhân quả)</div></div><div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\"><div style=\"font-weight:700;color:#555\">&#9642;&#65039; D. although</div><div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\">mặc dù (liên từ + mệnh đề, sai cấu trúc và nghĩa)</div></div>"}, {"id": "conj_ex1_5", "type": "fill", "q": "We do not own the building. __________, it would be impossible for us to make any major changes to it.", "vi": "", "opts": ["A. Thus", "B. Now that", "C. Nonetheless", "D. On the other hand"], "ans": 0, "explain_detail": "<div class=\"mb-2 p-3 rounded-xl font-700\" style=\"background:#d4edda;color:#155724\">&#9989; Đáp án đúng: A. Thus</div><div class=\"ex-card mb-3\">We do not own the building. <b>Thus</b>, it would be impossible for us to make any major changes to it.<br><span style=\"color:var(--accent);font-size:13px\">Chúng tôi không sở hữu tòa nhà. Do đó, sẽ không thể thực hiện bất kỳ thay đổi lớn nào đối với nó.</span></div><div class=\"mb-3 p-3 rounded-xl\" style=\"background:#f8f9fa;border-left:3px solid var(--accent);font-size:13px\">&#128209; <b>Thuộc phần lý thuyết:</b> Trạng từ nối câu chỉ KẾT QUẢ (therefore/thus/hence/consequently)</div><div class=\"mb-2 font-700 text-dark2\" style=\"font-size:13px\">&#128218; Giải thích chi tiết cả 4 đáp án:</div><div class=\"mb-2 p-3 rounded-xl\" style=\"background:#d4edda;border:1px solid rgba(0,0,0,.06)\"><div style=\"font-weight:700;color:#155724\">&#9989; A. Thus</div><div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\">do đó (trạng từ nối câu chỉ kết quả) → đúng, câu 2 là HỆ QUẢ logic của câu 1</div></div><div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\"><div style=\"font-weight:700;color:#555\">&#9642;&#65039; B. Now that</div><div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\">vì giờ đây (liên từ, cần đi kèm mệnh đề phía sau nó, không đứng đầu câu độc lập kiểu này)</div></div><div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\"><div style=\"font-weight:700;color:#555\">&#9642;&#65039; C. Nonetheless</div><div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\">tuy nhiên, dù vậy (chỉ tương phản, không hợp quan hệ nhân-quả ở đây)</div></div><div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\"><div style=\"font-weight:700;color:#555\">&#9642;&#65039; D. On the other hand</div><div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\">mặt khác (chỉ đối lập giữa 2 ý, không hợp nghĩa)</div></div>"}, {"id": "conj_ex1_6", "type": "fill", "q": "The whole report is badly written. __________, it's inaccurate.", "vi": "", "opts": ["A. For example", "B. Whereas", "C. Moreover", "D. However"], "ans": 2, "explain_detail": "<div class=\"mb-2 p-3 rounded-xl font-700\" style=\"background:#d4edda;color:#155724\">&#9989; Đáp án đúng: C. Moreover</div><div class=\"ex-card mb-3\">The whole report is badly written. <b>Moreover</b>, it's inaccurate.<br><span style=\"color:var(--accent);font-size:13px\">Toàn bộ báo cáo được viết kém. Hơn nữa, nó còn thiếu chính xác.</span></div><div class=\"mb-3 p-3 rounded-xl\" style=\"background:#f8f9fa;border-left:3px solid var(--accent);font-size:13px\">&#128209; <b>Thuộc phần lý thuyết:</b> Trạng từ nối câu chỉ SỰ BỔ SUNG (moreover/furthermore/besides/in addition)</div><div class=\"mb-2 font-700 text-dark2\" style=\"font-size:13px\">&#128218; Giải thích chi tiết cả 4 đáp án:</div><div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\"><div style=\"font-weight:700;color:#555\">&#9642;&#65039; A. For example</div><div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\">ví dụ như (đưa ra ví dụ, không hợp vì câu 2 không phải ví dụ)</div></div><div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\"><div style=\"font-weight:700;color:#555\">&#9642;&#65039; B. Whereas</div><div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\">trong khi đó (liên từ nối 2 mệnh đề trong CÙNG một câu, không dùng đầu câu độc lập như vậy)</div></div><div class=\"mb-2 p-3 rounded-xl\" style=\"background:#d4edda;border:1px solid rgba(0,0,0,.06)\"><div style=\"font-weight:700;color:#155724\">&#9989; C. Moreover</div><div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\">hơn nữa (bổ sung thêm một điểm tiêu cực nữa) → đúng, phù hợp mạch ý cùng phê bình bản báo cáo</div></div><div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\"><div style=\"font-weight:700;color:#555\">&#9642;&#65039; D. However</div><div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\">tuy nhiên (chỉ tương phản, nhưng câu 2 KHÔNG đối lập với câu 1, mà bổ sung thêm)</div></div>"}, {"id": "conj_ex1_7", "type": "fill", "q": "__________ you take a taxi, you'll still miss your train.", "vi": "", "opts": ["A. Even if", "B. If only", "C. Unless", "D. Until"], "ans": 0, "explain_detail": "<div class=\"mb-2 p-3 rounded-xl font-700\" style=\"background:#d4edda;color:#155724\">&#9989; Đáp án đúng: A. Even if</div><div class=\"ex-card mb-3\"><b>Even if</b> you take a taxi, you'll still miss your train.<br><span style=\"color:var(--accent);font-size:13px\">Cho dù bạn có bắt taxi thì bạn vẫn sẽ trễ chuyến tàu.</span></div><div class=\"mb-3 p-3 rounded-xl\" style=\"background:#f8f9fa;border-left:3px solid var(--accent);font-size:13px\">&#128209; <b>Thuộc phần lý thuyết:</b> Liên từ chỉ NHƯỢNG BỘ - ĐIỀU KIỆN (even if = cho dù, ngay cả khi)</div><div class=\"mb-2 font-700 text-dark2\" style=\"font-size:13px\">&#128218; Giải thích chi tiết cả 4 đáp án:</div><div class=\"mb-2 p-3 rounded-xl\" style=\"background:#d4edda;border:1px solid rgba(0,0,0,.06)\"><div style=\"font-weight:700;color:#155724\">&#9989; A. Even if</div><div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\">cho dù, ngay cả khi (nhượng bộ giả định) → đúng: dù có taxi đi nữa, kết quả vẫn không đổi</div></div><div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\"><div style=\"font-weight:700;color:#555\">&#9642;&#65039; B. If only</div><div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\">giá như (diễn tả ước muốn, không hợp cấu trúc câu này)</div></div><div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\"><div style=\"font-weight:700;color:#555\">&#9642;&#65039; C. Unless</div><div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\">trừ khi (điều kiện phủ định, nghĩa sẽ thành 'trừ khi bắt taxi thì mới trễ' — vô lý)</div></div><div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\"><div style=\"font-weight:700;color:#555\">&#9642;&#65039; D. Until</div><div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\">cho đến khi (chỉ thời gian, không hợp nghĩa)</div></div>"}, {"id": "conj_ex1_8", "type": "fill", "q": "_____your work has improved greatly, there are still some areas that concern me.", "vi": "", "opts": ["A. When", "B. Once", "C. As", "D. While"], "ans": 3, "explain_detail": "<div class=\"mb-2 p-3 rounded-xl font-700\" style=\"background:#d4edda;color:#155724\">&#9989; Đáp án đúng: D. While</div><div class=\"ex-card mb-3\"><b>While</b>your work has improved greatly, there are still some areas that concern me.<br><span style=\"color:var(--accent);font-size:13px\">Trong khi công việc của bạn đã cải thiện nhiều, vẫn còn một số điểm khiến tôi lo ngại.</span></div><div class=\"mb-3 p-3 rounded-xl\" style=\"background:#f8f9fa;border-left:3px solid var(--accent);font-size:13px\">&#128209; <b>Thuộc phần lý thuyết:</b> Liên từ chỉ SỰ TƯƠNG PHẢN (while/whereas)</div><div class=\"mb-2 font-700 text-dark2\" style=\"font-size:13px\">&#128218; Giải thích chi tiết cả 4 đáp án:</div><div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\"><div style=\"font-weight:700;color:#555\">&#9642;&#65039; A. When</div><div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\">khi (chỉ thời gian, không hợp ý tương phản)</div></div><div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\"><div style=\"font-weight:700;color:#555\">&#9642;&#65039; B. Once</div><div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\">một khi (chỉ thời gian, không hợp ý tương phản)</div></div><div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\"><div style=\"font-weight:700;color:#555\">&#9642;&#65039; C. As</div><div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\">khi, vì (không diễn tả tương phản rõ ràng ở đây)</div></div><div class=\"mb-2 p-3 rounded-xl\" style=\"background:#d4edda;border:1px solid rgba(0,0,0,.06)\"><div style=\"font-weight:700;color:#155724\">&#9989; D. While</div><div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\">trong khi (dùng để tương phản 2 ý: đã cải thiện >< vẫn còn lo ngại) → đúng</div></div>"}, {"id": "conj_ex1_9", "type": "fill", "q": "He works slowly and precisely ________ I tend to rush things and make mistakes.", "vi": "", "opts": ["A. otherwise", "B. nevertheless", "C. nonetheless", "D. whereas"], "ans": 3, "explain_detail": "<div class=\"mb-2 p-3 rounded-xl font-700\" style=\"background:#d4edda;color:#155724\">&#9989; Đáp án đúng: D. whereas</div><div class=\"ex-card mb-3\">He works slowly and precisely <b>whereas</b> I tend to rush things and make mistakes.<br><span style=\"color:var(--accent);font-size:13px\">Anh ấy làm việc chậm và cẩn thận, trong khi tôi có xu hướng vội vàng và mắc lỗi.</span></div><div class=\"mb-3 p-3 rounded-xl\" style=\"background:#f8f9fa;border-left:3px solid var(--accent);font-size:13px\">&#128209; <b>Thuộc phần lý thuyết:</b> Liên từ chỉ SỰ TƯƠNG PHẢN (whereas)</div><div class=\"mb-2 font-700 text-dark2\" style=\"font-size:13px\">&#128218; Giải thích chi tiết cả 4 đáp án:</div><div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\"><div style=\"font-weight:700;color:#555\">&#9642;&#65039; A. otherwise</div><div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\">nếu không thì (chỉ hậu quả của điều kiện phủ định, sai nghĩa)</div></div><div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\"><div style=\"font-weight:700;color:#555\">&#9642;&#65039; B. nevertheless</div><div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\">tuy nhiên (trạng từ nối CÂU, không nối 2 mệnh đề trong 1 câu như thế này)</div></div><div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\"><div style=\"font-weight:700;color:#555\">&#9642;&#65039; C. nonetheless</div><div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\">tuy nhiên (tương tự, là trạng từ nối câu, không phải liên từ nối mệnh đề)</div></div><div class=\"mb-2 p-3 rounded-xl\" style=\"background:#d4edda;border:1px solid rgba(0,0,0,.06)\"><div style=\"font-weight:700;color:#155724\">&#9989; D. whereas</div><div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\">trong khi đó (liên từ so sánh đối lập 2 mệnh đề) → đúng, đối lập giữa cách làm việc của 2 người</div></div>"}, {"id": "conj_ex1_10", "type": "fill", "q": "Their economy has expanded, while ours, __________, has declined.", "vi": "", "opts": ["A. in contrast", "B. as a result", "C. in addition", "D. for instance"], "ans": 0, "explain_detail": "<div class=\"mb-2 p-3 rounded-xl font-700\" style=\"background:#d4edda;color:#155724\">&#9989; Đáp án đúng: A. in contrast</div><div class=\"ex-card mb-3\">Their economy has expanded, while ours, <b>in contrast</b>, has declined.<br><span style=\"color:var(--accent);font-size:13px\">Nền kinh tế của họ đã tăng trưởng, trong khi ngược lại, nền kinh tế của chúng ta lại suy giảm.</span></div><div class=\"mb-3 p-3 rounded-xl\" style=\"background:#f8f9fa;border-left:3px solid var(--accent);font-size:13px\">&#128209; <b>Thuộc phần lý thuyết:</b> Trạng từ nối câu chỉ SỰ ĐỐI LẬP (in contrast/on the contrary/on the other hand)</div><div class=\"mb-2 font-700 text-dark2\" style=\"font-size:13px\">&#128218; Giải thích chi tiết cả 4 đáp án:</div><div class=\"mb-2 p-3 rounded-xl\" style=\"background:#d4edda;border:1px solid rgba(0,0,0,.06)\"><div style=\"font-weight:700;color:#155724\">&#9989; A. in contrast</div><div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\">trái lại, ngược lại (nhấn mạnh thêm sự đối lập đã có sẵn với 'while') → đúng</div></div><div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\"><div style=\"font-weight:700;color:#555\">&#9642;&#65039; B. as a result</div><div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\">kết quả là (chỉ kết quả, không hợp ý đối lập)</div></div><div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\"><div style=\"font-weight:700;color:#555\">&#9642;&#65039; C. in addition</div><div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\">thêm vào đó (chỉ bổ sung, không hợp)</div></div><div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\"><div style=\"font-weight:700;color:#555\">&#9642;&#65039; D. for instance</div><div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\">ví dụ như (đưa ví dụ, không hợp)</div></div>"}, {"id": "conj_ex1_11", "type": "fill", "q": "She walked home by herself __________ she knew that it was dangerous.", "vi": "", "opts": ["A. in spite of", "B. although", "C. because", "D. because of"], "ans": 1, "explain_detail": "<div class=\"mb-2 p-3 rounded-xl font-700\" style=\"background:#d4edda;color:#155724\">&#9989; Đáp án đúng: B. although</div><div class=\"ex-card mb-3\">She walked home by herself <b>although</b> she knew that it was dangerous.<br><span style=\"color:var(--accent);font-size:13px\">Cô ấy tự đi bộ về nhà mặc dù biết điều đó nguy hiểm.</span></div><div class=\"mb-3 p-3 rounded-xl\" style=\"background:#f8f9fa;border-left:3px solid var(--accent);font-size:13px\">&#128209; <b>Thuộc phần lý thuyết:</b> Liên từ chỉ SỰ NHƯỢNG BỘ (although + mệnh đề S+V)</div><div class=\"mb-2 font-700 text-dark2\" style=\"font-size:13px\">&#128218; Giải thích chi tiết cả 4 đáp án:</div><div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\"><div style=\"font-weight:700;color:#555\">&#9642;&#65039; A. in spite of</div><div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\">mặc dù (giới từ + danh từ/V-ing, KHÔNG đi với mệnh đề đầy đủ 'she knew...') → sai cấu trúc</div></div><div class=\"mb-2 p-3 rounded-xl\" style=\"background:#d4edda;border:1px solid rgba(0,0,0,.06)\"><div style=\"font-weight:700;color:#155724\">&#9989; B. although</div><div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\">mặc dù (liên từ + mệnh đề) → đúng, phù hợp với mệnh đề đầy đủ phía sau</div></div><div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\"><div style=\"font-weight:700;color:#555\">&#9642;&#65039; C. because</div><div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\">vì (sai nghĩa, đây là tương phản chứ không phải nguyên nhân)</div></div><div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\"><div style=\"font-weight:700;color:#555\">&#9642;&#65039; D. because of</div><div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\">vì (giới từ, sai cả cấu trúc và nghĩa)</div></div>"}, {"id": "conj_ex1_12", "type": "fill", "q": "There are serious problems in our country.__________, we feel this is a good time to return.", "vi": "", "opts": ["A. Moreover", "B. Nonetheless", "C. Furthermore", "D. Besides"], "ans": 1, "explain_detail": "<div class=\"mb-2 p-3 rounded-xl font-700\" style=\"background:#d4edda;color:#155724\">&#9989; Đáp án đúng: B. Nonetheless</div><div class=\"ex-card mb-3\">There are serious problems in our country.<b>Nonetheless</b>, we feel this is a good time to return.<br><span style=\"color:var(--accent);font-size:13px\">Đất nước chúng tôi đang có nhiều vấn đề nghiêm trọng. Dù vậy, chúng tôi cảm thấy đây là thời điểm tốt để trở về.</span></div><div class=\"mb-3 p-3 rounded-xl\" style=\"background:#f8f9fa;border-left:3px solid var(--accent);font-size:13px\">&#128209; <b>Thuộc phần lý thuyết:</b> Trạng từ nối câu chỉ SỰ TƯƠNG PHẢN (nevertheless/nonetheless)</div><div class=\"mb-2 font-700 text-dark2\" style=\"font-size:13px\">&#128218; Giải thích chi tiết cả 4 đáp án:</div><div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\"><div style=\"font-weight:700;color:#555\">&#9642;&#65039; A. Moreover</div><div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\">hơn nữa (bổ sung, không hợp vì câu 2 đối lập với câu 1)</div></div><div class=\"mb-2 p-3 rounded-xl\" style=\"background:#d4edda;border:1px solid rgba(0,0,0,.06)\"><div style=\"font-weight:700;color:#155724\">&#9989; B. Nonetheless</div><div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\">dù vậy, tuy nhiên (chỉ sự tương phản/nhượng bộ) → đúng, dù có vấn đề nhưng vẫn muốn về</div></div><div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\"><div style=\"font-weight:700;color:#555\">&#9642;&#65039; C. Furthermore</div><div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\">hơn nữa (bổ sung, sai nghĩa)</div></div><div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\"><div style=\"font-weight:700;color:#555\">&#9642;&#65039; D. Besides</div><div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\">bên cạnh đó (bổ sung, sai nghĩa)</div></div>"}, {"id": "conj_ex1_13", "type": "fill", "q": "They may do whatever they like __________ it is within the law.", "vi": "", "opts": ["A. as soon as", "B. in case", "C. provided that", "D. unless"], "ans": 2, "explain_detail": "<div class=\"mb-2 p-3 rounded-xl font-700\" style=\"background:#d4edda;color:#155724\">&#9989; Đáp án đúng: C. provided that</div><div class=\"ex-card mb-3\">They may do whatever they like <b>provided that</b> it is within the law.<br><span style=\"color:var(--accent);font-size:13px\">Họ có thể làm bất cứ điều gì họ thích miễn là điều đó hợp pháp.</span></div><div class=\"mb-3 p-3 rounded-xl\" style=\"background:#f8f9fa;border-left:3px solid var(--accent);font-size:13px\">&#128209; <b>Thuộc phần lý thuyết:</b> Liên từ chỉ ĐIỀU KIỆN (provided that/as long as = miễn là)</div><div class=\"mb-2 font-700 text-dark2\" style=\"font-size:13px\">&#128218; Giải thích chi tiết cả 4 đáp án:</div><div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\"><div style=\"font-weight:700;color:#555\">&#9642;&#65039; A. as soon as</div><div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\">ngay khi (chỉ thời gian, sai nghĩa)</div></div><div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\"><div style=\"font-weight:700;color:#555\">&#9642;&#65039; B. in case</div><div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\">phòng khi (chỉ đề phòng, sai nghĩa)</div></div><div class=\"mb-2 p-3 rounded-xl\" style=\"background:#d4edda;border:1px solid rgba(0,0,0,.06)\"><div style=\"font-weight:700;color:#155724\">&#9989; C. provided that</div><div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\">miễn là, với điều kiện là → đúng, đưa ra điều kiện cho phép</div></div><div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\"><div style=\"font-weight:700;color:#555\">&#9642;&#65039; D. unless</div><div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\">trừ khi (điều kiện phủ định, đảo ngược nghĩa câu)</div></div>"}, {"id": "conj_ex1_14", "type": "fill", "q": "He couldn't get money from the bank __________ he couldn't buy a house.", "vi": "", "opts": ["A. as", "B. but", "C. so", "D. yet"], "ans": 2, "explain_detail": "<div class=\"mb-2 p-3 rounded-xl font-700\" style=\"background:#d4edda;color:#155724\">&#9989; Đáp án đúng: C. so</div><div class=\"ex-card mb-3\">He couldn't get money from the bank <b>so</b> he couldn't buy a house.<br><span style=\"color:var(--accent);font-size:13px\">Anh ấy không thể vay tiền ngân hàng nên không thể mua nhà.</span></div><div class=\"mb-3 p-3 rounded-xl\" style=\"background:#f8f9fa;border-left:3px solid var(--accent);font-size:13px\">&#128209; <b>Thuộc phần lý thuyết:</b> Liên từ kết hợp chỉ KẾT QUẢ (so)</div><div class=\"mb-2 font-700 text-dark2\" style=\"font-size:13px\">&#128218; Giải thích chi tiết cả 4 đáp án:</div><div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\"><div style=\"font-weight:700;color:#555\">&#9642;&#65039; A. as</div><div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\">vì, khi (không hợp vì đây là quan hệ nguyên nhân-KẾT QUẢ theo chiều xuôi)</div></div><div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\"><div style=\"font-weight:700;color:#555\">&#9642;&#65039; B. but</div><div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\">nhưng (chỉ tương phản, không hợp vì 2 vế cùng chiều nguyên nhân-kết quả)</div></div><div class=\"mb-2 p-3 rounded-xl\" style=\"background:#d4edda;border:1px solid rgba(0,0,0,.06)\"><div style=\"font-weight:700;color:#155724\">&#9989; C. so</div><div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\">vì vậy (liên từ kết hợp chỉ kết quả) → đúng: không vay được tiền → không mua được nhà</div></div><div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\"><div style=\"font-weight:700;color:#555\">&#9642;&#65039; D. yet</div><div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\">vậy mà (chỉ tương phản, sai nghĩa)</div></div>"}, {"id": "conj_ex1_15", "type": "fill", "q": "Once he starts painting a room he won't stop __________ it's done.", "vi": "", "opts": ["A. as well as", "B. as soon as", "C. as long as", "D. until"], "ans": 3, "explain_detail": "<div class=\"mb-2 p-3 rounded-xl font-700\" style=\"background:#d4edda;color:#155724\">&#9989; Đáp án đúng: D. until</div><div class=\"ex-card mb-3\">Once he starts painting a room he won't stop <b>until</b> it's done.<br><span style=\"color:var(--accent);font-size:13px\">Một khi bắt đầu sơn phòng, anh ấy sẽ không dừng lại cho đến khi xong việc.</span></div><div class=\"mb-3 p-3 rounded-xl\" style=\"background:#f8f9fa;border-left:3px solid var(--accent);font-size:13px\">&#128209; <b>Thuộc phần lý thuyết:</b> Liên từ chỉ THỜI GIAN (until = cho đến khi)</div><div class=\"mb-2 font-700 text-dark2\" style=\"font-size:13px\">&#128218; Giải thích chi tiết cả 4 đáp án:</div><div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\"><div style=\"font-weight:700;color:#555\">&#9642;&#65039; A. as well as</div><div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\">cũng như (chỉ sự bổ sung, sai nghĩa)</div></div><div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\"><div style=\"font-weight:700;color:#555\">&#9642;&#65039; B. as soon as</div><div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\">ngay khi (chỉ 2 hành động liên tiếp ngay lập tức, không hợp nghĩa 'không dừng cho đến khi...')</div></div><div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\"><div style=\"font-weight:700;color:#555\">&#9642;&#65039; C. as long as</div><div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\">miễn là, chừng nào (chỉ điều kiện, không hợp)</div></div><div class=\"mb-2 p-3 rounded-xl\" style=\"background:#d4edda;border:1px solid rgba(0,0,0,.06)\"><div style=\"font-weight:700;color:#155724\">&#9989; D. until</div><div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\">cho đến khi → đúng: hành động 'không dừng lại' kéo dài tới một điểm mốc là 'xong việc'</div></div>"}, {"id": "conj_ex1_16", "type": "fill", "q": "I got into the house quietly __________ I might wake up my mom.", "vi": "", "opts": ["A. as soon as", "B. for fear that", "C. in order that", "D. on the contrary"], "ans": 1, "explain_detail": "<div class=\"mb-2 p-3 rounded-xl font-700\" style=\"background:#d4edda;color:#155724\">&#9989; Đáp án đúng: B. for fear that</div><div class=\"ex-card mb-3\">I got into the house quietly <b>for fear that</b> I might wake up my mom.<br><span style=\"color:var(--accent);font-size:13px\">Tôi lẻn vào nhà thật khẽ vì sợ rằng sẽ đánh thức mẹ dậy.</span></div><div class=\"mb-3 p-3 rounded-xl\" style=\"background:#f8f9fa;border-left:3px solid var(--accent);font-size:13px\">&#128209; <b>Thuộc phần lý thuyết:</b> Liên từ chỉ MỤC ĐÍCH tiêu cực (for fear that/lest = vì sợ rằng)</div><div class=\"mb-2 font-700 text-dark2\" style=\"font-size:13px\">&#128218; Giải thích chi tiết cả 4 đáp án:</div><div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\"><div style=\"font-weight:700;color:#555\">&#9642;&#65039; A. as soon as</div><div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\">ngay khi (chỉ thời gian, sai nghĩa)</div></div><div class=\"mb-2 p-3 rounded-xl\" style=\"background:#d4edda;border:1px solid rgba(0,0,0,.06)\"><div style=\"font-weight:700;color:#155724\">&#9989; B. for fear that</div><div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\">vì sợ rằng → đúng: hành động nhẹ nhàng LÀ ĐỂ TRÁNH việc đánh thức mẹ</div></div><div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\"><div style=\"font-weight:700;color:#555\">&#9642;&#65039; C. in order that</div><div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\">để mà (mục đích tích cực/trung tính, không khớp sắc thái 'sợ' như đề)</div></div><div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\"><div style=\"font-weight:700;color:#555\">&#9642;&#65039; D. on the contrary</div><div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\">trái lại (không hợp nghĩa và cấu trúc)</div></div>"}, {"id": "conj_ex1_17", "type": "fill", "q": "She gobbled __________ she hadn't eaten for ages.", "vi": "", "opts": ["A. as if", "B. even if", "C. unless", "D. so that"], "ans": 0, "explain_detail": "<div class=\"mb-2 p-3 rounded-xl font-700\" style=\"background:#d4edda;color:#155724\">&#9989; Đáp án đúng: A. as if</div><div class=\"ex-card mb-3\">She gobbled <b>as if</b> she hadn't eaten for ages.<br><span style=\"color:var(--accent);font-size:13px\">Cô ấy ngấu nghiến ăn như thể đã lâu lắm rồi chưa được ăn.</span></div><div class=\"mb-3 p-3 rounded-xl\" style=\"background:#f8f9fa;border-left:3px solid var(--accent);font-size:13px\">&#128209; <b>Thuộc phần lý thuyết:</b> Liên từ chỉ CÁCH THỨC/SO SÁNH GIẢ ĐỊNH (as if/as though)</div><div class=\"mb-2 font-700 text-dark2\" style=\"font-size:13px\">&#128218; Giải thích chi tiết cả 4 đáp án:</div><div class=\"mb-2 p-3 rounded-xl\" style=\"background:#d4edda;border:1px solid rgba(0,0,0,.06)\"><div style=\"font-weight:700;color:#155724\">&#9989; A. as if</div><div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\">như thể là → đúng: hành động ăn ngấu nghiến ĐƯỢC SO SÁNH với tình huống giả định 'lâu chưa ăn'</div></div><div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\"><div style=\"font-weight:700;color:#555\">&#9642;&#65039; B. even if</div><div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\">cho dù (chỉ nhượng bộ điều kiện, sai nghĩa)</div></div><div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\"><div style=\"font-weight:700;color:#555\">&#9642;&#65039; C. unless</div><div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\">trừ khi (chỉ điều kiện phủ định, sai nghĩa)</div></div><div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\"><div style=\"font-weight:700;color:#555\">&#9642;&#65039; D. so that</div><div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\">để mà (chỉ mục đích, sai nghĩa)</div></div>"}, {"id": "conj_ex1_18", "type": "fill", "q": "Shall I keep some chicken salad for your brother __________ he's hungry when he gets here?", "vi": "", "opts": ["A. as long as", "B. as though", "C. in case", "D. although"], "ans": 2, "explain_detail": "<div class=\"mb-2 p-3 rounded-xl font-700\" style=\"background:#d4edda;color:#155724\">&#9989; Đáp án đúng: C. in case</div><div class=\"ex-card mb-3\">Shall I keep some chicken salad for your brother <b>in case</b> he's hungry when he gets here?<br><span style=\"color:var(--accent);font-size:13px\">Tôi có nên để dành ít salad gà cho em trai bạn phòng khi cậu ấy đói lúc đến đây không?</span></div><div class=\"mb-3 p-3 rounded-xl\" style=\"background:#f8f9fa;border-left:3px solid var(--accent);font-size:13px\">&#128209; <b>Thuộc phần lý thuyết:</b> Liên từ chỉ SỰ ĐỀ PHÒNG (in case = phòng khi, lỡ khi)</div><div class=\"mb-2 font-700 text-dark2\" style=\"font-size:13px\">&#128218; Giải thích chi tiết cả 4 đáp án:</div><div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\"><div style=\"font-weight:700;color:#555\">&#9642;&#65039; A. as long as</div><div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\">miễn là (chỉ điều kiện, sai nghĩa)</div></div><div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\"><div style=\"font-weight:700;color:#555\">&#9642;&#65039; B. as though</div><div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\">như thể là (chỉ so sánh giả định, sai nghĩa)</div></div><div class=\"mb-2 p-3 rounded-xl\" style=\"background:#d4edda;border:1px solid rgba(0,0,0,.06)\"><div style=\"font-weight:700;color:#155724\">&#9989; C. in case</div><div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\">phòng khi, lỡ khi → đúng: để dành salad ĐỀ PHÒNG trường hợp cậu ấy đói</div></div><div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\"><div style=\"font-weight:700;color:#555\">&#9642;&#65039; D. although</div><div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\">mặc dù (sai nghĩa hoàn toàn)</div></div>"}, {"id": "conj_ex1_19", "type": "fill", "q": "__________ I earn a lot of money every month, I never seem to have any to spare.", "vi": "", "opts": ["A. Even though", "B. Because of", "C. In spite of", "D. Because"], "ans": 0, "explain_detail": "<div class=\"mb-2 p-3 rounded-xl font-700\" style=\"background:#d4edda;color:#155724\">&#9989; Đáp án đúng: A. Even though</div><div class=\"ex-card mb-3\"><b>Even though</b> I earn a lot of money every month, I never seem to have any to spare.<br><span style=\"color:var(--accent);font-size:13px\">Mặc dù kiếm được rất nhiều tiền mỗi tháng, tôi dường như chẳng bao giờ có dư.</span></div><div class=\"mb-3 p-3 rounded-xl\" style=\"background:#f8f9fa;border-left:3px solid var(--accent);font-size:13px\">&#128209; <b>Thuộc phần lý thuyết:</b> Liên từ chỉ SỰ NHƯỢNG BỘ (even though + mệnh đề)</div><div class=\"mb-2 font-700 text-dark2\" style=\"font-size:13px\">&#128218; Giải thích chi tiết cả 4 đáp án:</div><div class=\"mb-2 p-3 rounded-xl\" style=\"background:#d4edda;border:1px solid rgba(0,0,0,.06)\"><div style=\"font-weight:700;color:#155724\">&#9989; A. Even though</div><div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\">mặc dù (liên từ + mệnh đề S+V) → đúng, phù hợp với mệnh đề đầy đủ phía sau</div></div><div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\"><div style=\"font-weight:700;color:#555\">&#9642;&#65039; B. Because of</div><div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\">vì (giới từ + danh từ, không đi với mệnh đề đầy đủ) → sai cấu trúc và nghĩa</div></div><div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\"><div style=\"font-weight:700;color:#555\">&#9642;&#65039; C. In spite of</div><div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\">mặc dù (giới từ, không đi với mệnh đề đầy đủ) → sai cấu trúc</div></div><div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\"><div style=\"font-weight:700;color:#555\">&#9642;&#65039; D. Because</div><div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\">vì (sai nghĩa nhân-quả, đây là quan hệ tương phản)</div></div>"}, {"id": "conj_ex1_20", "type": "fill", "q": "__________ he has a good job and a happy family now, he is always complaining.", "vi": "", "opts": ["A. Although", "B. Despite", "C. Due to", "D. Because"], "ans": 0, "explain_detail": "<div class=\"mb-2 p-3 rounded-xl font-700\" style=\"background:#d4edda;color:#155724\">&#9989; Đáp án đúng: A. Although</div><div class=\"ex-card mb-3\"><b>Although</b> he has a good job and a happy family now, he is always complaining.<br><span style=\"color:var(--accent);font-size:13px\">Mặc dù hiện anh ấy có công việc tốt và gia đình hạnh phúc, anh ấy vẫn luôn than phiền.</span></div><div class=\"mb-3 p-3 rounded-xl\" style=\"background:#f8f9fa;border-left:3px solid var(--accent);font-size:13px\">&#128209; <b>Thuộc phần lý thuyết:</b> Liên từ chỉ SỰ NHƯỢNG BỘ (although + mệnh đề)</div><div class=\"mb-2 font-700 text-dark2\" style=\"font-size:13px\">&#128218; Giải thích chi tiết cả 4 đáp án:</div><div class=\"mb-2 p-3 rounded-xl\" style=\"background:#d4edda;border:1px solid rgba(0,0,0,.06)\"><div style=\"font-weight:700;color:#155724\">&#9989; A. Although</div><div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\">mặc dù (liên từ + mệnh đề) → đúng, phù hợp với mệnh đề đầy đủ phía sau</div></div><div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\"><div style=\"font-weight:700;color:#555\">&#9642;&#65039; B. Despite</div><div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\">mặc dù (giới từ + danh từ/V-ing, không đi với mệnh đề) → sai cấu trúc</div></div><div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\"><div style=\"font-weight:700;color:#555\">&#9642;&#65039; C. Due to</div><div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\">do, bởi vì (sai nghĩa và cấu trúc)</div></div><div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\"><div style=\"font-weight:700;color:#555\">&#9642;&#65039; D. Because</div><div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\">vì (sai nghĩa, đây là tương phản chứ không phải nguyên nhân)</div></div>"}, {"id": "conj_ex1_21", "type": "fill", "q": "He managed to eat a big lunch __________ having eaten an enormous breakfast.", "vi": "", "opts": ["A. although", "B. as", "C. owing to", "D. despite"], "ans": 3, "explain_detail": "<div class=\"mb-2 p-3 rounded-xl font-700\" style=\"background:#d4edda;color:#155724\">&#9989; Đáp án đúng: D. despite</div><div class=\"ex-card mb-3\">He managed to eat a big lunch <b>despite</b> having eaten an enormous breakfast.<br><span style=\"color:var(--accent);font-size:13px\">Anh ấy vẫn ăn được một bữa trưa thịnh soạn mặc dù đã ăn sáng rất no.</span></div><div class=\"mb-3 p-3 rounded-xl\" style=\"background:#f8f9fa;border-left:3px solid var(--accent);font-size:13px\">&#128209; <b>Thuộc phần lý thuyết:</b> Giới từ chỉ SỰ NHƯỢNG BỘ (despite/in spite of + V-ing)</div><div class=\"mb-2 font-700 text-dark2\" style=\"font-size:13px\">&#128218; Giải thích chi tiết cả 4 đáp án:</div><div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\"><div style=\"font-weight:700;color:#555\">&#9642;&#65039; A. although</div><div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\">mặc dù (liên từ + mệnh đề, không đi với cụm V-ing 'having eaten...') → sai cấu trúc</div></div><div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\"><div style=\"font-weight:700;color:#555\">&#9642;&#65039; B. as</div><div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\">vì, khi (sai nghĩa)</div></div><div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\"><div style=\"font-weight:700;color:#555\">&#9642;&#65039; C. owing to</div><div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\">do, bởi vì (sai nghĩa nhân quả)</div></div><div class=\"mb-2 p-3 rounded-xl\" style=\"background:#d4edda;border:1px solid rgba(0,0,0,.06)\"><div style=\"font-weight:700;color:#155724\">&#9989; D. despite</div><div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\">mặc dù, bất chấp (giới từ + V-ing) → đúng, phù hợp với cụm danh động từ phía sau</div></div>"}, {"id": "conj_ex1_22", "type": "fill", "q": "__________ our best endeavors, it has proven impossible to contact her.", "vi": "", "opts": ["A. Since", "B. Because of", "C. In spite of", "D. Even though"], "ans": 2, "explain_detail": "<div class=\"mb-2 p-3 rounded-xl font-700\" style=\"background:#d4edda;color:#155724\">&#9989; Đáp án đúng: C. In spite of</div><div class=\"ex-card mb-3\"><b>In spite of</b> our best endeavors, it has proven impossible to contact her.<br><span style=\"color:var(--accent);font-size:13px\">Mặc dù đã cố gắng hết sức, việc liên lạc với cô ấy vẫn không thể thực hiện được.</span></div><div class=\"mb-3 p-3 rounded-xl\" style=\"background:#f8f9fa;border-left:3px solid var(--accent);font-size:13px\">&#128209; <b>Thuộc phần lý thuyết:</b> Giới từ chỉ SỰ NHƯỢNG BỘ (in spite of + danh từ)</div><div class=\"mb-2 font-700 text-dark2\" style=\"font-size:13px\">&#128218; Giải thích chi tiết cả 4 đáp án:</div><div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\"><div style=\"font-weight:700;color:#555\">&#9642;&#65039; A. Since</div><div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\">vì, từ khi (sai nghĩa)</div></div><div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\"><div style=\"font-weight:700;color:#555\">&#9642;&#65039; B. Because of</div><div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\">vì (giới từ chỉ nguyên nhân, sai nghĩa — đây là tương phản)</div></div><div class=\"mb-2 p-3 rounded-xl\" style=\"background:#d4edda;border:1px solid rgba(0,0,0,.06)\"><div style=\"font-weight:700;color:#155724\">&#9989; C. In spite of</div><div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\">mặc dù, bất chấp (giới từ + danh từ 'our best endeavors') → đúng</div></div><div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\"><div style=\"font-weight:700;color:#555\">&#9642;&#65039; D. Even though</div><div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\">mặc dù (liên từ + mệnh đề, không đi với cụm danh từ) → sai cấu trúc</div></div>"}, {"id": "conj_ex1_23", "type": "fill", "q": "I enjoyed her new book __________ it's not quite as good as her last one.", "vi": "", "opts": ["A. due to", "B. in spite of", "C. though", "D. since"], "ans": 2, "explain_detail": "<div class=\"mb-2 p-3 rounded-xl font-700\" style=\"background:#d4edda;color:#155724\">&#9989; Đáp án đúng: C. though</div><div class=\"ex-card mb-3\">I enjoyed her new book <b>though</b> it's not quite as good as her last one.<br><span style=\"color:var(--accent);font-size:13px\">Tôi thích cuốn sách mới của cô ấy dù nó không hay bằng cuốn trước.</span></div><div class=\"mb-3 p-3 rounded-xl\" style=\"background:#f8f9fa;border-left:3px solid var(--accent);font-size:13px\">&#128209; <b>Thuộc phần lý thuyết:</b> Liên từ chỉ SỰ NHƯỢNG BỘ (though + mệnh đề, thường đứng cuối câu)</div><div class=\"mb-2 font-700 text-dark2\" style=\"font-size:13px\">&#128218; Giải thích chi tiết cả 4 đáp án:</div><div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\"><div style=\"font-weight:700;color:#555\">&#9642;&#65039; A. due to</div><div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\">do, bởi vì (giới từ, sai nghĩa và cấu trúc)</div></div><div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\"><div style=\"font-weight:700;color:#555\">&#9642;&#65039; B. in spite of</div><div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\">mặc dù (giới từ + danh từ, không đi với mệnh đề đầy đủ) → sai cấu trúc</div></div><div class=\"mb-2 p-3 rounded-xl\" style=\"background:#d4edda;border:1px solid rgba(0,0,0,.06)\"><div style=\"font-weight:700;color:#155724\">&#9989; C. though</div><div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\">mặc dù (liên từ + mệnh đề, thường dùng ở cuối câu/văn nói) → đúng</div></div><div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\"><div style=\"font-weight:700;color:#555\">&#9642;&#65039; D. since</div><div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\">vì, từ khi (sai nghĩa)</div></div>"}, {"id": "conj_ex1_24", "type": "fill", "q": "He came home early __________ see the kids before they went to bed.", "vi": "", "opts": ["A. in order to", "B. in addition to", "C. so as not to", "D. so that"], "ans": 0, "explain_detail": "<div class=\"mb-2 p-3 rounded-xl font-700\" style=\"background:#d4edda;color:#155724\">&#9989; Đáp án đúng: A. in order to</div><div class=\"ex-card mb-3\">He came home early <b>in order to</b> see the kids before they went to bed.<br><span style=\"color:var(--accent);font-size:13px\">Anh ấy về nhà sớm để gặp bọn trẻ trước khi chúng đi ngủ.</span></div><div class=\"mb-3 p-3 rounded-xl\" style=\"background:#f8f9fa;border-left:3px solid var(--accent);font-size:13px\">&#128209; <b>Thuộc phần lý thuyết:</b> Giới từ chỉ MỤC ĐÍCH (in order to/so as to + V-nguyên mẫu)</div><div class=\"mb-2 font-700 text-dark2\" style=\"font-size:13px\">&#128218; Giải thích chi tiết cả 4 đáp án:</div><div class=\"mb-2 p-3 rounded-xl\" style=\"background:#d4edda;border:1px solid rgba(0,0,0,.06)\"><div style=\"font-weight:700;color:#155724\">&#9989; A. in order to</div><div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\">để (+ động từ nguyên mẫu 'see') → đúng: về sớm VỚI MỤC ĐÍCH gặp bọn trẻ</div></div><div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\"><div style=\"font-weight:700;color:#555\">&#9642;&#65039; B. in addition to</div><div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\">ngoài...ra (giới từ + N/V-ing, sai cấu trúc và nghĩa)</div></div><div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\"><div style=\"font-weight:700;color:#555\">&#9642;&#65039; C. so as not to</div><div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\">để KHÔNG (phủ định mục đích, ngược nghĩa vì anh ấy MUỐN gặp các con)</div></div><div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\"><div style=\"font-weight:700;color:#555\">&#9642;&#65039; D. so that</div><div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\">để mà (liên từ + mệnh đề S+V, không đi trực tiếp với V nguyên mẫu 'see') → sai cấu trúc</div></div>"}, {"id": "conj_ex1_25", "type": "fill", "q": "The kids have to get up before 7 a.m, __________ they'll be late for school.", "vi": "", "opts": ["A. in order that", "B. unless", "C. otherwise", "D. because"], "ans": 2, "explain_detail": "<div class=\"mb-2 p-3 rounded-xl font-700\" style=\"background:#d4edda;color:#155724\">&#9989; Đáp án đúng: C. otherwise</div><div class=\"ex-card mb-3\">The kids have to get up before 7 a.m, <b>otherwise</b> they'll be late for school.<br><span style=\"color:var(--accent);font-size:13px\">Bọn trẻ phải dậy trước 7 giờ sáng, nếu không chúng sẽ đi học muộn.</span></div><div class=\"mb-3 p-3 rounded-xl\" style=\"background:#f8f9fa;border-left:3px solid var(--accent);font-size:13px\">&#128209; <b>Thuộc phần lý thuyết:</b> Trạng từ nối câu chỉ HẬU QUẢ của điều kiện phủ định (otherwise = nếu không thì)</div><div class=\"mb-2 font-700 text-dark2\" style=\"font-size:13px\">&#128218; Giải thích chi tiết cả 4 đáp án:</div><div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\"><div style=\"font-weight:700;color:#555\">&#9642;&#65039; A. in order that</div><div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\">để mà (chỉ mục đích, sai nghĩa)</div></div><div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\"><div style=\"font-weight:700;color:#555\">&#9642;&#65039; B. unless</div><div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\">trừ khi (là liên từ nối mệnh đề, không dùng đứng sau dấu phẩy làm trạng từ nối câu kiểu này; nghĩa cũng lặp lại ý phủ định không hợp)</div></div><div class=\"mb-2 p-3 rounded-xl\" style=\"background:#d4edda;border:1px solid rgba(0,0,0,.06)\"><div style=\"font-weight:700;color:#155724\">&#9989; C. otherwise</div><div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\">nếu không (thì) → đúng: nếu KHÔNG dậy trước 7h thì sẽ trễ học</div></div><div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\"><div style=\"font-weight:700;color:#555\">&#9642;&#65039; D. because</div><div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\">vì (sai nghĩa nhân quả)</div></div>"}, {"id": "conj_ex1_26", "type": "fill", "q": "Students are not allowed to handle these chemicals __________ they are under the supervision of a teacher.", "vi": "", "opts": ["A. if", "B. unless", "C. suppose", "D. providing"], "ans": 1, "explain_detail": "<div class=\"mb-2 p-3 rounded-xl font-700\" style=\"background:#d4edda;color:#155724\">&#9989; Đáp án đúng: B. unless</div><div class=\"ex-card mb-3\">Students are not allowed to handle these chemicals <b>unless</b> they are under the supervision of a teacher.<br><span style=\"color:var(--accent);font-size:13px\">Học sinh không được phép tiếp xúc với các hóa chất này trừ khi có sự giám sát của giáo viên.</span></div><div class=\"mb-3 p-3 rounded-xl\" style=\"background:#f8f9fa;border-left:3px solid var(--accent);font-size:13px\">&#128209; <b>Thuộc phần lý thuyết:</b> Liên từ chỉ ĐIỀU KIỆN phủ định (unless = trừ khi)</div><div class=\"mb-2 font-700 text-dark2\" style=\"font-size:13px\">&#128218; Giải thích chi tiết cả 4 đáp án:</div><div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\"><div style=\"font-weight:700;color:#555\">&#9642;&#65039; A. if</div><div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\">nếu (không mang nghĩa phủ định 'trừ khi' cần thiết ở đây)</div></div><div class=\"mb-2 p-3 rounded-xl\" style=\"background:#d4edda;border:1px solid rgba(0,0,0,.06)\"><div style=\"font-weight:700;color:#155724\">&#9989; B. unless</div><div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\">trừ khi → đúng: chỉ được phép NẾU có giám sát, tức là bị cấm TRỪ KHI có giám sát</div></div><div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\"><div style=\"font-weight:700;color:#555\">&#9642;&#65039; C. suppose</div><div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\">giả sử (không hợp ngữ cảnh quy định/cấm đoán)</div></div><div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\"><div style=\"font-weight:700;color:#555\">&#9642;&#65039; D. providing</div><div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\">miễn là (thiếu chữ 'that/providing that', và nghĩa 'miễn là có giám sát thì được phép' ít tự nhiên hơn unless trong văn cảnh cấm đoán này)</div></div>"}, {"id": "conj_ex1_27", "type": "fill", "q": "__________ our noisy neighbors have moved, life is a lot more peaceful.", "vi": "", "opts": ["A. While", "B. Although", "C. Hence", "D. Now that"], "ans": 3, "explain_detail": "<div class=\"mb-2 p-3 rounded-xl font-700\" style=\"background:#d4edda;color:#155724\">&#9989; Đáp án đúng: D. Now that</div><div class=\"ex-card mb-3\"><b>Now that</b> our noisy neighbors have moved, life is a lot more peaceful.<br><span style=\"color:var(--accent);font-size:13px\">Giờ đây khi những người hàng xóm ồn ào đã chuyển đi, cuộc sống yên bình hơn nhiều.</span></div><div class=\"mb-3 p-3 rounded-xl\" style=\"background:#f8f9fa;border-left:3px solid var(--accent);font-size:13px\">&#128209; <b>Thuộc phần lý thuyết:</b> Liên từ chỉ NGUYÊN NHÂN (now that = vì giờ đây, bởi vì bây giờ)</div><div class=\"mb-2 font-700 text-dark2\" style=\"font-size:13px\">&#128218; Giải thích chi tiết cả 4 đáp án:</div><div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\"><div style=\"font-weight:700;color:#555\">&#9642;&#65039; A. While</div><div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\">trong khi (chỉ thời gian/tương phản, không hợp nghĩa)</div></div><div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\"><div style=\"font-weight:700;color:#555\">&#9642;&#65039; B. Although</div><div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\">mặc dù (chỉ tương phản, sai nghĩa vì đây là quan hệ nhân-quả)</div></div><div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\"><div style=\"font-weight:700;color:#555\">&#9642;&#65039; C. Hence</div><div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\">do đó (là trạng từ nối câu chỉ kết quả, không phải liên từ nối mệnh đề như cấu trúc câu này)</div></div><div class=\"mb-2 p-3 rounded-xl\" style=\"background:#d4edda;border:1px solid rgba(0,0,0,.06)\"><div style=\"font-weight:700;color:#155724\">&#9989; D. Now that</div><div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\">vì giờ đây, bởi vì bây giờ → đúng: NGUYÊN NHÂN khiến cuộc sống yên bình hơn</div></div>"}, {"id": "conj_ex1_28", "type": "fill", "q": "You can play in the living room __________ you don't make a mess.", "vi": "", "opts": ["A. as soon as", "B. as well as", "C. as far as", "D. as long as"], "ans": 3, "explain_detail": "<div class=\"mb-2 p-3 rounded-xl font-700\" style=\"background:#d4edda;color:#155724\">&#9989; Đáp án đúng: D. as long as</div><div class=\"ex-card mb-3\">You can play in the living room <b>as long as</b> you don't make a mess.<br><span style=\"color:var(--accent);font-size:13px\">Con có thể chơi trong phòng khách miễn là con không bày bừa.</span></div><div class=\"mb-3 p-3 rounded-xl\" style=\"background:#f8f9fa;border-left:3px solid var(--accent);font-size:13px\">&#128209; <b>Thuộc phần lý thuyết:</b> Liên từ chỉ ĐIỀU KIỆN (as long as = miễn là)</div><div class=\"mb-2 font-700 text-dark2\" style=\"font-size:13px\">&#128218; Giải thích chi tiết cả 4 đáp án:</div><div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\"><div style=\"font-weight:700;color:#555\">&#9642;&#65039; A. as soon as</div><div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\">ngay khi (chỉ thời gian, sai nghĩa)</div></div><div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\"><div style=\"font-weight:700;color:#555\">&#9642;&#65039; B. as well as</div><div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\">cũng như (chỉ bổ sung, sai nghĩa)</div></div><div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\"><div style=\"font-weight:700;color:#555\">&#9642;&#65039; C. as far as</div><div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\">theo như (chỉ mức độ/phạm vi, sai nghĩa)</div></div><div class=\"mb-2 p-3 rounded-xl\" style=\"background:#d4edda;border:1px solid rgba(0,0,0,.06)\"><div style=\"font-weight:700;color:#155724\">&#9989; D. as long as</div><div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\">miễn là, với điều kiện là → đúng: được chơi NẾU không bày bừa</div></div>"}, {"id": "conj_ex1_29", "type": "fill", "q": "He agreed to speak to reporters __________ he was not identified.", "vi": "", "opts": ["A. on the whole", "B. on the condition that", "C. on the contrary", "D. on the other hand"], "ans": 1, "explain_detail": "<div class=\"mb-2 p-3 rounded-xl font-700\" style=\"background:#d4edda;color:#155724\">&#9989; Đáp án đúng: B. on the condition that</div><div class=\"ex-card mb-3\">He agreed to speak to reporters <b>on the condition that</b> he was not identified.<br><span style=\"color:var(--accent);font-size:13px\">Anh ấy đồng ý nói chuyện với các phóng viên với điều kiện là không bị tiết lộ danh tính.</span></div><div class=\"mb-3 p-3 rounded-xl\" style=\"background:#f8f9fa;border-left:3px solid var(--accent);font-size:13px\">&#128209; <b>Thuộc phần lý thuyết:</b> Liên từ chỉ ĐIỀU KIỆN (on the condition that = với điều kiện là)</div><div class=\"mb-2 font-700 text-dark2\" style=\"font-size:13px\">&#128218; Giải thích chi tiết cả 4 đáp án:</div><div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\"><div style=\"font-weight:700;color:#555\">&#9642;&#65039; A. on the whole</div><div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\">nhìn chung (sai nghĩa)</div></div><div class=\"mb-2 p-3 rounded-xl\" style=\"background:#d4edda;border:1px solid rgba(0,0,0,.06)\"><div style=\"font-weight:700;color:#155724\">&#9989; B. on the condition that</div><div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\">với điều kiện là → đúng: đồng ý phỏng vấn KÈM ĐIỀU KIỆN giấu danh tính</div></div><div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\"><div style=\"font-weight:700;color:#555\">&#9642;&#65039; C. on the contrary</div><div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\">trái lại (sai nghĩa)</div></div><div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\"><div style=\"font-weight:700;color:#555\">&#9642;&#65039; D. on the other hand</div><div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\">mặt khác (sai nghĩa)</div></div>"}, {"id": "conj_ex1_30", "type": "fill", "q": "__________, he realized there was someone in the room.", "vi": "", "opts": ["A. Whereas he opened the door", "B. Even though he opened the door", "C. As long as he opened the door", "D. As soon as he opened the door"], "ans": 3, "explain_detail": "<div class=\"mb-2 p-3 rounded-xl font-700\" style=\"background:#d4edda;color:#155724\">&#9989; Đáp án đúng: D. As soon as he opened the door</div><div class=\"ex-card mb-3\"><b>As soon as he opened the door</b>, he realized there was someone in the room.<br><span style=\"color:var(--accent);font-size:13px\">Ngay khi mở cửa, anh ấy nhận ra có ai đó trong phòng.</span></div><div class=\"mb-3 p-3 rounded-xl\" style=\"background:#f8f9fa;border-left:3px solid var(--accent);font-size:13px\">&#128209; <b>Thuộc phần lý thuyết:</b> Liên từ chỉ THỜI GIAN (as soon as = ngay khi)</div><div class=\"mb-2 font-700 text-dark2\" style=\"font-size:13px\">&#128218; Giải thích chi tiết cả 4 đáp án:</div><div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\"><div style=\"font-weight:700;color:#555\">&#9642;&#65039; A. Whereas he opened the door</div><div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\">trong khi anh ấy mở cửa (chỉ đối lập, không hợp 2 hành động liên tiếp)</div></div><div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\"><div style=\"font-weight:700;color:#555\">&#9642;&#65039; B. Even though he opened the door</div><div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\">mặc dù anh ấy mở cửa (chỉ nhượng bộ, sai nghĩa)</div></div><div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\"><div style=\"font-weight:700;color:#555\">&#9642;&#65039; C. As long as he opened the door</div><div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\">miễn là anh ấy mở cửa (chỉ điều kiện, sai nghĩa)</div></div><div class=\"mb-2 p-3 rounded-xl\" style=\"background:#d4edda;border:1px solid rgba(0,0,0,.06)\"><div style=\"font-weight:700;color:#155724\">&#9989; D. As soon as he opened the door</div><div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\">ngay khi anh ấy mở cửa → đúng: hai hành động 'mở cửa' và 'nhận ra' xảy ra NGAY SAU NHAU</div></div>"}, {"id": "conj_ex1_31", "type": "fill", "q": "__________ I had done my homework, I went out with my friend.", "vi": "", "opts": ["A. If", "B. Before", "C. After", "D. While"], "ans": 2, "explain_detail": "<div class=\"mb-2 p-3 rounded-xl font-700\" style=\"background:#d4edda;color:#155724\">&#9989; Đáp án đúng: C. After</div><div class=\"ex-card mb-3\"><b>After</b> I had done my homework, I went out with my friend.<br><span style=\"color:var(--accent);font-size:13px\">Sau khi làm xong bài tập, tôi đã đi chơi với bạn.</span></div><div class=\"mb-3 p-3 rounded-xl\" style=\"background:#f8f9fa;border-left:3px solid var(--accent);font-size:13px\">&#128209; <b>Thuộc phần lý thuyết:</b> Liên từ chỉ THỜI GIAN (after = sau khi)</div><div class=\"mb-2 font-700 text-dark2\" style=\"font-size:13px\">&#128218; Giải thích chi tiết cả 4 đáp án:</div><div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\"><div style=\"font-weight:700;color:#555\">&#9642;&#65039; A. If</div><div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\">nếu (chỉ điều kiện, sai nghĩa)</div></div><div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\"><div style=\"font-weight:700;color:#555\">&#9642;&#65039; B. Before</div><div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\">trước khi (ngược trình tự thời gian: phải làm xong BÀI TẬP trước rồi mới đi chơi)</div></div><div class=\"mb-2 p-3 rounded-xl\" style=\"background:#d4edda;border:1px solid rgba(0,0,0,.06)\"><div style=\"font-weight:700;color:#155724\">&#9989; C. After</div><div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\">sau khi → đúng: đi chơi diễn ra SAU KHI làm xong bài tập</div></div><div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\"><div style=\"font-weight:700;color:#555\">&#9642;&#65039; D. While</div><div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\">trong khi (chỉ 2 hành động đồng thời, không hợp vì đây là 2 hành động nối tiếp)</div></div>"}, {"id": "conj_ex1_32", "type": "fill", "q": "__________ he succeeded, he had to work very hard.", "vi": "", "opts": ["A. While", "B. Before", "C. Once", "D. If"], "ans": 1, "explain_detail": "<div class=\"mb-2 p-3 rounded-xl font-700\" style=\"background:#d4edda;color:#155724\">&#9989; Đáp án đúng: B. Before</div><div class=\"ex-card mb-3\"><b>Before</b> he succeeded, he had to work very hard.<br><span style=\"color:var(--accent);font-size:13px\">Trước khi thành công, anh ấy đã phải làm việc rất chăm chỉ.</span></div><div class=\"mb-3 p-3 rounded-xl\" style=\"background:#f8f9fa;border-left:3px solid var(--accent);font-size:13px\">&#128209; <b>Thuộc phần lý thuyết:</b> Liên từ chỉ THỜI GIAN (before = trước khi)</div><div class=\"mb-2 font-700 text-dark2\" style=\"font-size:13px\">&#128218; Giải thích chi tiết cả 4 đáp án:</div><div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\"><div style=\"font-weight:700;color:#555\">&#9642;&#65039; A. While</div><div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\">trong khi (chỉ đồng thời, không hợp trình tự trước-sau ở đây)</div></div><div class=\"mb-2 p-3 rounded-xl\" style=\"background:#d4edda;border:1px solid rgba(0,0,0,.06)\"><div style=\"font-weight:700;color:#155724\">&#9989; B. Before</div><div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\">trước khi → đúng: phải làm việc chăm chỉ TRƯỚC KHI đạt được thành công</div></div><div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\"><div style=\"font-weight:700;color:#555\">&#9642;&#65039; C. Once</div><div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\">một khi (nghĩa là 'ngay khi thành công thì...', không hợp mạch ý 'phải cố gắng trước')</div></div><div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\"><div style=\"font-weight:700;color:#555\">&#9642;&#65039; D. If</div><div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\">nếu (chỉ điều kiện, không hợp nghĩa thời gian ở đây)</div></div>"}, {"id": "conj_ex1_33", "type": "fill", "q": "I knew everything. __________, I tried to pretend I didn't know.", "vi": "", "opts": ["A. Moreover", "B. Therefore", "C. Nevertheless", "D. While"], "ans": 2, "explain_detail": "<div class=\"mb-2 p-3 rounded-xl font-700\" style=\"background:#d4edda;color:#155724\">&#9989; Đáp án đúng: C. Nevertheless</div><div class=\"ex-card mb-3\">I knew everything. <b>Nevertheless</b>, I tried to pretend I didn't know.<br><span style=\"color:var(--accent);font-size:13px\">Tôi biết hết mọi chuyện. Tuy nhiên, tôi cố giả vờ như không biết.</span></div><div class=\"mb-3 p-3 rounded-xl\" style=\"background:#f8f9fa;border-left:3px solid var(--accent);font-size:13px\">&#128209; <b>Thuộc phần lý thuyết:</b> Trạng từ nối câu chỉ SỰ TƯƠNG PHẢN (nevertheless)</div><div class=\"mb-2 font-700 text-dark2\" style=\"font-size:13px\">&#128218; Giải thích chi tiết cả 4 đáp án:</div><div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\"><div style=\"font-weight:700;color:#555\">&#9642;&#65039; A. Moreover</div><div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\">hơn nữa (chỉ bổ sung, sai nghĩa)</div></div><div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\"><div style=\"font-weight:700;color:#555\">&#9642;&#65039; B. Therefore</div><div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\">do đó (chỉ kết quả, sai nghĩa — hành động 'giả vờ không biết' TRÁI NGƯỢC với việc 'biết hết')</div></div><div class=\"mb-2 p-3 rounded-xl\" style=\"background:#d4edda;border:1px solid rgba(0,0,0,.06)\"><div style=\"font-weight:700;color:#155724\">&#9989; C. Nevertheless</div><div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\">tuy nhiên, dù vậy → đúng: 2 câu có ý TƯƠNG PHẢN nhau</div></div><div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\"><div style=\"font-weight:700;color:#555\">&#9642;&#65039; D. While</div><div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\">trong khi (là liên từ nối mệnh đề trong 1 câu, không dùng làm trạng từ nối 2 câu độc lập kiểu này)</div></div>"}, {"id": "conj_ex1_34", "type": "fill", "q": "We can go to the concert, __________ we've already paid for the tickets.", "vi": "", "opts": ["A. seeing that", "B. unless", "C. as if", "D. while"], "ans": 0, "explain_detail": "<div class=\"mb-2 p-3 rounded-xl font-700\" style=\"background:#d4edda;color:#155724\">&#9989; Đáp án đúng: A. seeing that</div><div class=\"ex-card mb-3\">We can go to the concert, <b>seeing that</b> we've already paid for the tickets.<br><span style=\"color:var(--accent);font-size:13px\">Chúng ta có thể đi xem hòa nhạc, vì dù sao cũng đã trả tiền vé rồi.</span></div><div class=\"mb-3 p-3 rounded-xl\" style=\"background:#f8f9fa;border-left:3px solid var(--accent);font-size:13px\">&#128209; <b>Thuộc phần lý thuyết:</b> Liên từ chỉ NGUYÊN NHÂN (seeing that = vì, xét thấy)</div><div class=\"mb-2 font-700 text-dark2\" style=\"font-size:13px\">&#128218; Giải thích chi tiết cả 4 đáp án:</div><div class=\"mb-2 p-3 rounded-xl\" style=\"background:#d4edda;border:1px solid rgba(0,0,0,.06)\"><div style=\"font-weight:700;color:#155724\">&#9989; A. seeing that</div><div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\">vì, xét thấy → đúng: lý do đi xem là VÌ đã mua vé rồi</div></div><div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\"><div style=\"font-weight:700;color:#555\">&#9642;&#65039; B. unless</div><div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\">trừ khi (chỉ điều kiện phủ định, sai nghĩa)</div></div><div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\"><div style=\"font-weight:700;color:#555\">&#9642;&#65039; C. as if</div><div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\">như thể là (chỉ so sánh giả định, sai nghĩa)</div></div><div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\"><div style=\"font-weight:700;color:#555\">&#9642;&#65039; D. while</div><div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\">trong khi (chỉ tương phản/đồng thời, không hợp quan hệ nhân quả ở đây)</div></div>"}, {"id": "conj_ex1_35", "type": "fill", "q": "I was having breakfast __________ the telephone rang.", "vi": "", "opts": ["A. once", "B. when", "C. since", "D. so"], "ans": 1, "explain_detail": "<div class=\"mb-2 p-3 rounded-xl font-700\" style=\"background:#d4edda;color:#155724\">&#9989; Đáp án đúng: B. when</div><div class=\"ex-card mb-3\">I was having breakfast <b>when</b> the telephone rang.<br><span style=\"color:var(--accent);font-size:13px\">Tôi đang ăn sáng thì điện thoại reo.</span></div><div class=\"mb-3 p-3 rounded-xl\" style=\"background:#f8f9fa;border-left:3px solid var(--accent);font-size:13px\">&#128209; <b>Thuộc phần lý thuyết:</b> Liên từ chỉ THỜI GIAN (when = khi, dùng khi một hành động đang xảy ra thì hành động khác xen vào)</div><div class=\"mb-2 font-700 text-dark2\" style=\"font-size:13px\">&#128218; Giải thích chi tiết cả 4 đáp án:</div><div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\"><div style=\"font-weight:700;color:#555\">&#9642;&#65039; A. once</div><div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\">một khi (chỉ điều kiện thời gian, không hợp diễn tả sự việc xen ngang)</div></div><div class=\"mb-2 p-3 rounded-xl\" style=\"background:#d4edda;border:1px solid rgba(0,0,0,.06)\"><div style=\"font-weight:700;color:#155724\">&#9989; B. when</div><div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\">khi → đúng: hành động 'điện thoại reo' xen vào giữa lúc đang ăn sáng</div></div><div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\"><div style=\"font-weight:700;color:#555\">&#9642;&#65039; C. since</div><div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\">từ khi, vì (sai nghĩa ở đây)</div></div><div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\"><div style=\"font-weight:700;color:#555\">&#9642;&#65039; D. so</div><div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\">vì vậy (chỉ kết quả, sai nghĩa)</div></div>"}, {"id": "conj_ex1_36", "type": "fill", "q": "If this project fails, it will affect __________ our department, but also the whole organization.", "vi": "", "opts": ["A. not only", "B. both", "C. whether", "D. and"], "ans": 0, "explain_detail": "<div class=\"mb-2 p-3 rounded-xl font-700\" style=\"background:#d4edda;color:#155724\">&#9989; Đáp án đúng: A. not only</div><div class=\"ex-card mb-3\">If this project fails, it will affect <b>not only</b> our department, but also the whole organization.<br><span style=\"color:var(--accent);font-size:13px\">Nếu dự án này thất bại, nó sẽ ảnh hưởng không những đến phòng ban chúng ta mà còn cả tổ chức.</span></div><div class=\"mb-3 p-3 rounded-xl\" style=\"background:#f8f9fa;border-left:3px solid var(--accent);font-size:13px\">&#128209; <b>Thuộc phần lý thuyết:</b> Liên từ tương quan NOT ONLY...BUT ALSO (không những... mà còn...)</div><div class=\"mb-2 font-700 text-dark2\" style=\"font-size:13px\">&#128218; Giải thích chi tiết cả 4 đáp án:</div><div class=\"mb-2 p-3 rounded-xl\" style=\"background:#d4edda;border:1px solid rgba(0,0,0,.06)\"><div style=\"font-weight:700;color:#155724\">&#9989; A. not only</div><div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\">không những (kết hợp với 'but also' phía sau) → đúng, khớp với 'but also' đã có sẵn trong câu</div></div><div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\"><div style=\"font-weight:700;color:#555\">&#9642;&#65039; B. both</div><div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\">cả hai (đi với 'and', không khớp với 'but also' đã cho)</div></div><div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\"><div style=\"font-weight:700;color:#555\">&#9642;&#65039; C. whether</div><div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\">liệu có... hay không (đi với 'or', không khớp với 'but also')</div></div><div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\"><div style=\"font-weight:700;color:#555\">&#9642;&#65039; D. and</div><div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\">và (không tạo thành cặp tương quan với 'but also')</div></div>"}, {"id": "conj_ex1_37", "type": "fill", "q": "__________ had they started their walk than it started to rain.", "vi": "", "opts": ["A. Whether", "B. Either", "C. No sooner", "D. Neither"], "ans": 2, "explain_detail": "<div class=\"mb-2 p-3 rounded-xl font-700\" style=\"background:#d4edda;color:#155724\">&#9989; Đáp án đúng: C. No sooner</div><div class=\"ex-card mb-3\"><b>No sooner</b> had they started their walk than it started to rain.<br><span style=\"color:var(--accent);font-size:13px\">Họ vừa mới bắt đầu đi bộ thì trời đổ mưa.</span></div><div class=\"mb-3 p-3 rounded-xl\" style=\"background:#f8f9fa;border-left:3px solid var(--accent);font-size:13px\">&#128209; <b>Thuộc phần lý thuyết:</b> Cấu trúc đảo ngữ NO SOONER...THAN (vừa mới... thì đã...)</div><div class=\"mb-2 font-700 text-dark2\" style=\"font-size:13px\">&#128218; Giải thích chi tiết cả 4 đáp án:</div><div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\"><div style=\"font-weight:700;color:#555\">&#9642;&#65039; A. Whether</div><div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\">liệu có... hay không (không tạo cặp với 'than')</div></div><div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\"><div style=\"font-weight:700;color:#555\">&#9642;&#65039; B. Either</div><div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\">hoặc (đi với 'or', không khớp với 'than')</div></div><div class=\"mb-2 p-3 rounded-xl\" style=\"background:#d4edda;border:1px solid rgba(0,0,0,.06)\"><div style=\"font-weight:700;color:#155724\">&#9989; C. No sooner</div><div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\">vừa mới... thì đã... (đi với 'than', đảo ngữ 'had they started') → đúng</div></div><div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\"><div style=\"font-weight:700;color:#555\">&#9642;&#65039; D. Neither</div><div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\">không... cũng không (đi với 'nor', không khớp với 'than')</div></div>"}, {"id": "conj_ex1_38", "type": "fill", "q": "__________had Rina finished her homework when the electricity went out.", "vi": "", "opts": ["A. Before", "B. After", "C. No sooner", "D. Hardly"], "ans": 3, "explain_detail": "<div class=\"mb-2 p-3 rounded-xl font-700\" style=\"background:#d4edda;color:#155724\">&#9989; Đáp án đúng: D. Hardly</div><div class=\"ex-card mb-3\"><b>Hardly</b>had Rina finished her homework when the electricity went out.<br><span style=\"color:var(--accent);font-size:13px\">Rina vừa mới làm xong bài tập thì mất điện.</span></div><div class=\"mb-3 p-3 rounded-xl\" style=\"background:#f8f9fa;border-left:3px solid var(--accent);font-size:13px\">&#128209; <b>Thuộc phần lý thuyết:</b> Cấu trúc đảo ngữ HARDLY...WHEN (vừa mới... thì đã...)</div><div class=\"mb-2 font-700 text-dark2\" style=\"font-size:13px\">&#128218; Giải thích chi tiết cả 4 đáp án:</div><div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\"><div style=\"font-weight:700;color:#555\">&#9642;&#65039; A. Before</div><div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\">trước khi (không tạo cặp đảo ngữ với 'when' theo kiểu này)</div></div><div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\"><div style=\"font-weight:700;color:#555\">&#9642;&#65039; B. After</div><div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\">sau khi (không tạo cặp đảo ngữ này)</div></div><div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\"><div style=\"font-weight:700;color:#555\">&#9642;&#65039; C. No sooner</div><div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\">vừa mới... (đi với THAN, không phải WHEN, nên không khớp ở đây)</div></div><div class=\"mb-2 p-3 rounded-xl\" style=\"background:#d4edda;border:1px solid rgba(0,0,0,.06)\"><div style=\"font-weight:700;color:#155724\">&#9989; D. Hardly</div><div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\">vừa mới... thì đã... (đi với 'when', đảo ngữ 'had Rina finished') → đúng</div></div>"}, {"id": "conj_ex1_39", "type": "fill", "q": "She didn't know __________ he was laughing __________crying.", "vi": "", "opts": ["A. so - that", "B. whether - or", "C. neither - nor", "D. both - and"], "ans": 1, "explain_detail": "<div class=\"mb-2 p-3 rounded-xl font-700\" style=\"background:#d4edda;color:#155724\">&#9989; Đáp án đúng: B. whether - or</div><div class=\"ex-card mb-3\">She didn't know <b>whether - or</b> he was laughing <b>whether - or</b>crying.<br><span style=\"color:var(--accent);font-size:13px\">Cô ấy không biết liệu anh ấy đang cười hay đang khóc.</span></div><div class=\"mb-3 p-3 rounded-xl\" style=\"background:#f8f9fa;border-left:3px solid var(--accent);font-size:13px\">&#128209; <b>Thuộc phần lý thuyết:</b> Liên từ tương quan WHETHER...OR (dù...hay...) trong mệnh đề danh từ</div><div class=\"mb-2 font-700 text-dark2\" style=\"font-size:13px\">&#128218; Giải thích chi tiết cả 4 đáp án:</div><div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\"><div style=\"font-weight:700;color:#555\">&#9642;&#65039; A. so - that</div><div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\">đến mức... đến nỗi (cặp liên từ chỉ kết quả, không hợp nghĩa 'không biết A hay B')</div></div><div class=\"mb-2 p-3 rounded-xl\" style=\"background:#d4edda;border:1px solid rgba(0,0,0,.06)\"><div style=\"font-weight:700;color:#155724\">&#9989; B. whether - or</div><div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\">liệu... hay... → đúng: diễn tả sự không chắc chắn giữa 2 khả năng cười/khóc</div></div><div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\"><div style=\"font-weight:700;color:#555\">&#9642;&#65039; C. neither - nor</div><div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\">không... cũng không... (phủ định cả hai, sai nghĩa vì câu cần diễn tả sự PHÂN VÂN)</div></div><div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\"><div style=\"font-weight:700;color:#555\">&#9642;&#65039; D. both - and</div><div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\">cả... và... (khẳng định cả hai cùng lúc, sai nghĩa)</div></div>"}, {"id": "conj_ex1_40", "type": "fill", "q": "They were __________ sad nor disappointed with their exam results.", "vi": "", "opts": ["A. neither", "B. either", "C. not only", "D. whether"], "ans": 0, "explain_detail": "<div class=\"mb-2 p-3 rounded-xl font-700\" style=\"background:#d4edda;color:#155724\">&#9989; Đáp án đúng: A. neither</div><div class=\"ex-card mb-3\">They were <b>neither</b> sad nor disappointed with their exam results.<br><span style=\"color:var(--accent);font-size:13px\">Họ không buồn cũng không thất vọng về kết quả thi của mình.</span></div><div class=\"mb-3 p-3 rounded-xl\" style=\"background:#f8f9fa;border-left:3px solid var(--accent);font-size:13px\">&#128209; <b>Thuộc phần lý thuyết:</b> Liên từ tương quan NEITHER...NOR (không... cũng không...)</div><div class=\"mb-2 font-700 text-dark2\" style=\"font-size:13px\">&#128218; Giải thích chi tiết cả 4 đáp án:</div><div class=\"mb-2 p-3 rounded-xl\" style=\"background:#d4edda;border:1px solid rgba(0,0,0,.06)\"><div style=\"font-weight:700;color:#155724\">&#9989; A. neither</div><div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\">không... (đi với 'nor' đã có sẵn trong câu) → đúng</div></div><div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\"><div style=\"font-weight:700;color:#555\">&#9642;&#65039; B. either</div><div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\">hoặc (đi với 'or', không khớp với 'nor' đã cho)</div></div><div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\"><div style=\"font-weight:700;color:#555\">&#9642;&#65039; C. not only</div><div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\">không những (đi với 'but also', không khớp với 'nor')</div></div><div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\"><div style=\"font-weight:700;color:#555\">&#9642;&#65039; D. whether</div><div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\">liệu có... hay không (đi với 'or', không khớp với 'nor')</div></div>"}];
const CONJ_EX2 = [{"id": "conj_ex2_1", "type": "fill", "q": "The outdoor event was canceled ___________ the heavy rain.", "vi": "", "opts": ["A. because of", "B. because", "C. although", "D. despite"], "ans": 0, "explain_detail": "<div class=\"mb-2 p-3 rounded-xl font-700\" style=\"background:#d4edda;color:#155724\">&#9989; Đáp án đúng: A. because of</div><div class=\"ex-card mb-3\">The outdoor event was canceled <b>because of</b>_ the heavy rain.<br><span style=\"color:var(--accent);font-size:13px\">Sự kiện ngoài trời đã bị hủy vì trời mưa lớn.</span></div><div class=\"mb-3 p-3 rounded-xl\" style=\"background:#f8f9fa;border-left:3px solid var(--accent);font-size:13px\">&#128209; <b>Thuộc phần lý thuyết:</b> Giới từ chỉ NGUYÊN NHÂN (because of + danh từ)</div><div class=\"mb-2 font-700 text-dark2\" style=\"font-size:13px\">&#128218; Giải thích chi tiết cả 4 đáp án:</div><div class=\"mb-2 p-3 rounded-xl\" style=\"background:#d4edda;border:1px solid rgba(0,0,0,.06)\"><div style=\"font-weight:700;color:#155724\">&#9989; A. because of</div><div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\">vì, bởi vì (giới từ + danh từ 'the heavy rain') → đúng</div></div><div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\"><div style=\"font-weight:700;color:#555\">&#9642;&#65039; B. because</div><div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\">vì (liên từ + mệnh đề, không đi với cụm danh từ) → sai cấu trúc</div></div><div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\"><div style=\"font-weight:700;color:#555\">&#9642;&#65039; C. although</div><div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\">mặc dù (sai nghĩa, đây là quan hệ nhân quả)</div></div><div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\"><div style=\"font-weight:700;color:#555\">&#9642;&#65039; D. despite</div><div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\">mặc dù (sai nghĩa nhân quả)</div></div>"}, {"id": "conj_ex2_2", "type": "fill", "q": "_________ the restaurant had excellent reviews, the food didn't live up to our expectations.", "vi": "", "opts": ["A. In spite of", "B. Although", "C. As", "D. Owing to"], "ans": 1, "explain_detail": "<div class=\"mb-2 p-3 rounded-xl font-700\" style=\"background:#d4edda;color:#155724\">&#9989; Đáp án đúng: B. Although</div><div class=\"ex-card mb-3\"><b>Although</b> the restaurant had excellent reviews, the food didn't live up to our expectations.<br><span style=\"color:var(--accent);font-size:13px\">Mặc dù nhà hàng có đánh giá xuất sắc, đồ ăn lại không như mong đợi.</span></div><div class=\"mb-3 p-3 rounded-xl\" style=\"background:#f8f9fa;border-left:3px solid var(--accent);font-size:13px\">&#128209; <b>Thuộc phần lý thuyết:</b> Liên từ chỉ SỰ NHƯỢNG BỘ (although + mệnh đề)</div><div class=\"mb-2 font-700 text-dark2\" style=\"font-size:13px\">&#128218; Giải thích chi tiết cả 4 đáp án:</div><div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\"><div style=\"font-weight:700;color:#555\">&#9642;&#65039; A. In spite of</div><div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\">mặc dù (giới từ, không đi với mệnh đề đầy đủ) → sai cấu trúc</div></div><div class=\"mb-2 p-3 rounded-xl\" style=\"background:#d4edda;border:1px solid rgba(0,0,0,.06)\"><div style=\"font-weight:700;color:#155724\">&#9989; B. Although</div><div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\">mặc dù (liên từ + mệnh đề) → đúng, phù hợp với mệnh đề đầy đủ phía sau</div></div><div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\"><div style=\"font-weight:700;color:#555\">&#9642;&#65039; C. As</div><div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\">vì, khi (sai nghĩa nhân quả)</div></div><div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\"><div style=\"font-weight:700;color:#555\">&#9642;&#65039; D. Owing to</div><div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\">do, bởi vì (giới từ, sai cấu trúc và nghĩa)</div></div>"}, {"id": "conj_ex2_3", "type": "fill", "q": "_________it was raining, we decided to go for a hike in the woods.", "vi": "", "opts": ["A. However", "B. Moreover", "C. Though", "D. Since"], "ans": 2, "explain_detail": "<div class=\"mb-2 p-3 rounded-xl font-700\" style=\"background:#d4edda;color:#155724\">&#9989; Đáp án đúng: C. Though</div><div class=\"ex-card mb-3\"><b>Though</b>it was raining, we decided to go for a hike in the woods.<br><span style=\"color:var(--accent);font-size:13px\">Mặc dù trời đang mưa, chúng tôi vẫn quyết định đi bộ đường dài trong rừng.</span></div><div class=\"mb-3 p-3 rounded-xl\" style=\"background:#f8f9fa;border-left:3px solid var(--accent);font-size:13px\">&#128209; <b>Thuộc phần lý thuyết:</b> Liên từ chỉ SỰ NHƯỢNG BỘ (though + mệnh đề)</div><div class=\"mb-2 font-700 text-dark2\" style=\"font-size:13px\">&#128218; Giải thích chi tiết cả 4 đáp án:</div><div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\"><div style=\"font-weight:700;color:#555\">&#9642;&#65039; A. However</div><div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\">tuy nhiên (là trạng từ nối câu, không phải liên từ nối mệnh đề trong 1 câu)</div></div><div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\"><div style=\"font-weight:700;color:#555\">&#9642;&#65039; B. Moreover</div><div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\">hơn nữa (chỉ bổ sung, sai nghĩa)</div></div><div class=\"mb-2 p-3 rounded-xl\" style=\"background:#d4edda;border:1px solid rgba(0,0,0,.06)\"><div style=\"font-weight:700;color:#155724\">&#9989; C. Though</div><div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\">mặc dù (liên từ + mệnh đề) → đúng, dù mưa vẫn quyết định đi</div></div><div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\"><div style=\"font-weight:700;color:#555\">&#9642;&#65039; D. Since</div><div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\">vì, từ khi (sai nghĩa nhân quả)</div></div>"}, {"id": "conj_ex2_4", "type": "fill", "q": "The flight was delayed _______ there was a technical issue with the aircraft.", "vi": "", "opts": ["A. because of", "B. because", "C. even though", "D. in spite of"], "ans": 1, "explain_detail": "<div class=\"mb-2 p-3 rounded-xl font-700\" style=\"background:#d4edda;color:#155724\">&#9989; Đáp án đúng: B. because</div><div class=\"ex-card mb-3\">The flight was delayed <b>because</b> there was a technical issue with the aircraft.<br><span style=\"color:var(--accent);font-size:13px\">Chuyến bay bị hoãn vì máy bay gặp sự cố kỹ thuật.</span></div><div class=\"mb-3 p-3 rounded-xl\" style=\"background:#f8f9fa;border-left:3px solid var(--accent);font-size:13px\">&#128209; <b>Thuộc phần lý thuyết:</b> Liên từ chỉ NGUYÊN NHÂN (because + mệnh đề)</div><div class=\"mb-2 font-700 text-dark2\" style=\"font-size:13px\">&#128218; Giải thích chi tiết cả 4 đáp án:</div><div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\"><div style=\"font-weight:700;color:#555\">&#9642;&#65039; A. because of</div><div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\">vì (giới từ + danh từ, không đi với mệnh đề đầy đủ) → sai cấu trúc</div></div><div class=\"mb-2 p-3 rounded-xl\" style=\"background:#d4edda;border:1px solid rgba(0,0,0,.06)\"><div style=\"font-weight:700;color:#155724\">&#9989; B. because</div><div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\">vì (liên từ + mệnh đề 'there was a technical issue...') → đúng</div></div><div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\"><div style=\"font-weight:700;color:#555\">&#9642;&#65039; C. even though</div><div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\">mặc dù (sai nghĩa nhân quả)</div></div><div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\"><div style=\"font-weight:700;color:#555\">&#9642;&#65039; D. in spite of</div><div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\">mặc dù (sai nghĩa và cấu trúc)</div></div>"}, {"id": "conj_ex2_5", "type": "fill", "q": "________ the rain, the outdoor concert still attracted a large crowd.", "vi": "", "opts": ["A. On account of", "B. Now that", "C. Although", "D. Despite"], "ans": 3, "explain_detail": "<div class=\"mb-2 p-3 rounded-xl font-700\" style=\"background:#d4edda;color:#155724\">&#9989; Đáp án đúng: D. Despite</div><div class=\"ex-card mb-3\"><b>Despite</b> the rain, the outdoor concert still attracted a large crowd.<br><span style=\"color:var(--accent);font-size:13px\">Mặc cho trời mưa, buổi hòa nhạc ngoài trời vẫn thu hút đông đảo khán giả.</span></div><div class=\"mb-3 p-3 rounded-xl\" style=\"background:#f8f9fa;border-left:3px solid var(--accent);font-size:13px\">&#128209; <b>Thuộc phần lý thuyết:</b> Giới từ chỉ SỰ NHƯỢNG BỘ (despite + danh từ)</div><div class=\"mb-2 font-700 text-dark2\" style=\"font-size:13px\">&#128218; Giải thích chi tiết cả 4 đáp án:</div><div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\"><div style=\"font-weight:700;color:#555\">&#9642;&#65039; A. On account of</div><div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\">vì, bởi vì (giới từ chỉ nguyên nhân, sai nghĩa — đây là tương phản)</div></div><div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\"><div style=\"font-weight:700;color:#555\">&#9642;&#65039; B. Now that</div><div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\">vì giờ đây (liên từ + mệnh đề, sai cấu trúc và nghĩa)</div></div><div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\"><div style=\"font-weight:700;color:#555\">&#9642;&#65039; C. Although</div><div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\">mặc dù (liên từ + mệnh đề, không đi với cụm danh từ 'the rain') → sai cấu trúc</div></div><div class=\"mb-2 p-3 rounded-xl\" style=\"background:#d4edda;border:1px solid rgba(0,0,0,.06)\"><div style=\"font-weight:700;color:#155724\">&#9989; D. Despite</div><div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\">mặc dù, bất chấp (giới từ + danh từ) → đúng</div></div>"}, {"id": "conj_ex2_6", "type": "fill", "q": "The restaurant not only serves delicious food but has excellent customer service;__________, it offers a cozy ambiance.", "vi": "", "opts": ["A. moreover", "B. in addition to", "C. However", "D. Because"], "ans": 0, "explain_detail": "<div class=\"mb-2 p-3 rounded-xl font-700\" style=\"background:#d4edda;color:#155724\">&#9989; Đáp án đúng: A. moreover</div><div class=\"ex-card mb-3\">The restaurant not only serves delicious food but has excellent customer service;<b>moreover</b>, it offers a cozy ambiance.<br><span style=\"color:var(--accent);font-size:13px\">Nhà hàng không những phục vụ món ăn ngon và dịch vụ tuyệt vời; hơn nữa, còn có không gian ấm cúng.</span></div><div class=\"mb-3 p-3 rounded-xl\" style=\"background:#f8f9fa;border-left:3px solid var(--accent);font-size:13px\">&#128209; <b>Thuộc phần lý thuyết:</b> Trạng từ nối câu chỉ SỰ BỔ SUNG (moreover)</div><div class=\"mb-2 font-700 text-dark2\" style=\"font-size:13px\">&#128218; Giải thích chi tiết cả 4 đáp án:</div><div class=\"mb-2 p-3 rounded-xl\" style=\"background:#d4edda;border:1px solid rgba(0,0,0,.06)\"><div style=\"font-weight:700;color:#155724\">&#9989; A. moreover</div><div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\">hơn nữa → đúng: bổ sung thêm một ưu điểm nữa của nhà hàng</div></div><div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\"><div style=\"font-weight:700;color:#555\">&#9642;&#65039; B. in addition to</div><div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\">ngoài...ra (giới từ + N/V-ing, không đứng đầu mệnh đề độc lập kiểu này) → sai cấu trúc</div></div><div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\"><div style=\"font-weight:700;color:#555\">&#9642;&#65039; C. However</div><div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\">tuy nhiên (chỉ tương phản, không hợp vì câu này BỔ SUNG chứ không đối lập)</div></div><div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\"><div style=\"font-weight:700;color:#555\">&#9642;&#65039; D. Because</div><div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\">vì (sai nghĩa và cấu trúc)</div></div>"}, {"id": "conj_ex2_7", "type": "fill", "q": "She missed her flight _________________a traffic jam on the way to the airport.", "vi": "", "opts": ["A. because", "B. because of", "C. although", "D. in spite of"], "ans": 1, "explain_detail": "<div class=\"mb-2 p-3 rounded-xl font-700\" style=\"background:#d4edda;color:#155724\">&#9989; Đáp án đúng: B. because of</div><div class=\"ex-card mb-3\">She missed her flight <b>because of</b><b>because of</b>a traffic jam on the way to the airport.<br><span style=\"color:var(--accent);font-size:13px\">Cô ấy lỡ chuyến bay vì tắc đường trên đường ra sân bay.</span></div><div class=\"mb-3 p-3 rounded-xl\" style=\"background:#f8f9fa;border-left:3px solid var(--accent);font-size:13px\">&#128209; <b>Thuộc phần lý thuyết:</b> Giới từ chỉ NGUYÊN NHÂN (because of + danh từ)</div><div class=\"mb-2 font-700 text-dark2\" style=\"font-size:13px\">&#128218; Giải thích chi tiết cả 4 đáp án:</div><div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\"><div style=\"font-weight:700;color:#555\">&#9642;&#65039; A. because</div><div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\">vì (liên từ + mệnh đề, không đi với cụm danh từ) → sai cấu trúc</div></div><div class=\"mb-2 p-3 rounded-xl\" style=\"background:#d4edda;border:1px solid rgba(0,0,0,.06)\"><div style=\"font-weight:700;color:#155724\">&#9989; B. because of</div><div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\">vì, bởi vì (giới từ + danh từ 'a traffic jam') → đúng</div></div><div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\"><div style=\"font-weight:700;color:#555\">&#9642;&#65039; C. although</div><div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\">mặc dù (sai nghĩa nhân quả)</div></div><div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\"><div style=\"font-weight:700;color:#555\">&#9642;&#65039; D. in spite of</div><div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\">mặc dù (sai nghĩa nhân quả)</div></div>"}, {"id": "conj_ex2_8", "type": "fill", "q": "The team worked tirelessly day and night._____________, they completed the project ahead of schedule.", "vi": "", "opts": ["A. However", "B. By contrast", "C. As a result", "D. In addition"], "ans": 2, "explain_detail": "<div class=\"mb-2 p-3 rounded-xl font-700\" style=\"background:#d4edda;color:#155724\">&#9989; Đáp án đúng: C. As a result</div><div class=\"ex-card mb-3\">The team worked tirelessly day and night.<b>As a result</b>___, they completed the project ahead of schedule.<br><span style=\"color:var(--accent);font-size:13px\">Cả đội đã làm việc không mệt mỏi ngày đêm. Kết quả là, họ hoàn thành dự án trước thời hạn.</span></div><div class=\"mb-3 p-3 rounded-xl\" style=\"background:#f8f9fa;border-left:3px solid var(--accent);font-size:13px\">&#128209; <b>Thuộc phần lý thuyết:</b> Trạng từ nối câu chỉ KẾT QUẢ (as a result)</div><div class=\"mb-2 font-700 text-dark2\" style=\"font-size:13px\">&#128218; Giải thích chi tiết cả 4 đáp án:</div><div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\"><div style=\"font-weight:700;color:#555\">&#9642;&#65039; A. However</div><div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\">tuy nhiên (chỉ tương phản, không hợp vì câu 2 là KẾT QUẢ của câu 1)</div></div><div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\"><div style=\"font-weight:700;color:#555\">&#9642;&#65039; B. By contrast</div><div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\">trái lại (chỉ đối lập, sai nghĩa)</div></div><div class=\"mb-2 p-3 rounded-xl\" style=\"background:#d4edda;border:1px solid rgba(0,0,0,.06)\"><div style=\"font-weight:700;color:#155724\">&#9989; C. As a result</div><div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\">kết quả là, do đó → đúng: hoàn thành sớm LÀ KẾT QUẢ của việc làm việc chăm chỉ</div></div><div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\"><div style=\"font-weight:700;color:#555\">&#9642;&#65039; D. In addition</div><div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\">thêm vào đó (chỉ bổ sung, không hợp quan hệ nhân-quả)</div></div>"}, {"id": "conj_ex2_9", "type": "fill", "q": "The restaurant on the corner is always crowded with long waiting lines.___________, the one across the street is usually empty and quiet.", "vi": "", "opts": ["A. Although", "B. Despite", "C. As a consequence", "D. By contrast"], "ans": 3, "explain_detail": "<div class=\"mb-2 p-3 rounded-xl font-700\" style=\"background:#d4edda;color:#155724\">&#9989; Đáp án đúng: D. By contrast</div><div class=\"ex-card mb-3\">The restaurant on the corner is always crowded with long waiting lines.<b>By contrast</b>_, the one across the street is usually empty and quiet.<br><span style=\"color:var(--accent);font-size:13px\">Nhà hàng ở góc phố luôn đông khách và phải xếp hàng dài. Ngược lại, nhà hàng bên kia đường thường vắng vẻ và yên tĩnh.</span></div><div class=\"mb-3 p-3 rounded-xl\" style=\"background:#f8f9fa;border-left:3px solid var(--accent);font-size:13px\">&#128209; <b>Thuộc phần lý thuyết:</b> Trạng từ nối câu chỉ SỰ ĐỐI LẬP (by contrast)</div><div class=\"mb-2 font-700 text-dark2\" style=\"font-size:13px\">&#128218; Giải thích chi tiết cả 4 đáp án:</div><div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\"><div style=\"font-weight:700;color:#555\">&#9642;&#65039; A. Although</div><div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\">mặc dù (là liên từ nối mệnh đề trong 1 câu, không dùng làm trạng từ nối 2 câu độc lập)</div></div><div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\"><div style=\"font-weight:700;color:#555\">&#9642;&#65039; B. Despite</div><div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\">mặc dù (giới từ, không dùng đứng đầu câu độc lập kiểu này)</div></div><div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\"><div style=\"font-weight:700;color:#555\">&#9642;&#65039; C. As a consequence</div><div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\">kết quả là (chỉ nhân quả, không hợp ý ĐỐI LẬP giữa 2 nhà hàng)</div></div><div class=\"mb-2 p-3 rounded-xl\" style=\"background:#d4edda;border:1px solid rgba(0,0,0,.06)\"><div style=\"font-weight:700;color:#155724\">&#9989; D. By contrast</div><div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\">trái lại, ngược lại → đúng: so sánh đối lập giữa 2 nhà hàng</div></div>"}, {"id": "conj_ex2_10", "type": "fill", "q": "___________ it was raining heavily, we decided to stay indoors for the entire day.", "vi": "", "opts": ["A. Since", "B. In addition to", "C. Because of", "D. Therefore"], "ans": 0, "explain_detail": "<div class=\"mb-2 p-3 rounded-xl font-700\" style=\"background:#d4edda;color:#155724\">&#9989; Đáp án đúng: A. Since</div><div class=\"ex-card mb-3\"><b>Since</b>_ it was raining heavily, we decided to stay indoors for the entire day.<br><span style=\"color:var(--accent);font-size:13px\">Vì trời mưa to nên chúng tôi quyết định ở trong nhà cả ngày.</span></div><div class=\"mb-3 p-3 rounded-xl\" style=\"background:#f8f9fa;border-left:3px solid var(--accent);font-size:13px\">&#128209; <b>Thuộc phần lý thuyết:</b> Liên từ chỉ NGUYÊN NHÂN (since + mệnh đề)</div><div class=\"mb-2 font-700 text-dark2\" style=\"font-size:13px\">&#128218; Giải thích chi tiết cả 4 đáp án:</div><div class=\"mb-2 p-3 rounded-xl\" style=\"background:#d4edda;border:1px solid rgba(0,0,0,.06)\"><div style=\"font-weight:700;color:#155724\">&#9989; A. Since</div><div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\">vì (liên từ + mệnh đề 'it was raining heavily') → đúng</div></div><div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\"><div style=\"font-weight:700;color:#555\">&#9642;&#65039; B. In addition to</div><div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\">ngoài...ra (giới từ, sai cấu trúc và nghĩa)</div></div><div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\"><div style=\"font-weight:700;color:#555\">&#9642;&#65039; C. Because of</div><div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\">vì (giới từ + danh từ, không đi với mệnh đề đầy đủ) → sai cấu trúc</div></div><div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\"><div style=\"font-weight:700;color:#555\">&#9642;&#65039; D. Therefore</div><div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\">do đó (trạng từ nối câu, không dùng đứng đầu để nối mệnh đề phụ vào mệnh đề chính kiểu này)</div></div>"}, {"id": "conj_ex2_11", "type": "fill", "q": "He promised to be on time;____________, he arrived late to the meeting.", "vi": "", "opts": ["A. although", "B. however", "C. besides", "D. because"], "ans": 1, "explain_detail": "<div class=\"mb-2 p-3 rounded-xl font-700\" style=\"background:#d4edda;color:#155724\">&#9989; Đáp án đúng: B. however</div><div class=\"ex-card mb-3\">He promised to be on time;<b>however</b>__, he arrived late to the meeting.<br><span style=\"color:var(--accent);font-size:13px\">Anh ấy hứa sẽ đến đúng giờ; tuy nhiên, anh ấy lại đến cuộc họp muộn.</span></div><div class=\"mb-3 p-3 rounded-xl\" style=\"background:#f8f9fa;border-left:3px solid var(--accent);font-size:13px\">&#128209; <b>Thuộc phần lý thuyết:</b> Trạng từ nối câu chỉ SỰ TƯƠNG PHẢN (however)</div><div class=\"mb-2 font-700 text-dark2\" style=\"font-size:13px\">&#128218; Giải thích chi tiết cả 4 đáp án:</div><div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\"><div style=\"font-weight:700;color:#555\">&#9642;&#65039; A. although</div><div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\">mặc dù (là liên từ nối mệnh đề, không dùng làm trạng từ nối 2 câu độc lập sau dấu chấm phẩy)</div></div><div class=\"mb-2 p-3 rounded-xl\" style=\"background:#d4edda;border:1px solid rgba(0,0,0,.06)\"><div style=\"font-weight:700;color:#155724\">&#9989; B. however</div><div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\">tuy nhiên → đúng: kết quả trái ngược với lời hứa</div></div><div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\"><div style=\"font-weight:700;color:#555\">&#9642;&#65039; C. besides</div><div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\">bên cạnh đó (chỉ bổ sung, sai nghĩa)</div></div><div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\"><div style=\"font-weight:700;color:#555\">&#9642;&#65039; D. because</div><div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\">vì (sai nghĩa nhân quả)</div></div>"}, {"id": "conj_ex2_12", "type": "fill", "q": "_____________painting, she is also skilled at sketching.", "vi": "", "opts": ["A. In spite of", "B. Because of", "C. As a result of", "D. In addition to"], "ans": 3, "explain_detail": "<div class=\"mb-2 p-3 rounded-xl font-700\" style=\"background:#d4edda;color:#155724\">&#9989; Đáp án đúng: D. In addition to</div><div class=\"ex-card mb-3\"><b>In addition to</b>___painting, she is also skilled at sketching.<br><span style=\"color:var(--accent);font-size:13px\">Ngoài vẽ tranh, cô ấy còn giỏi vẽ phác thảo.</span></div><div class=\"mb-3 p-3 rounded-xl\" style=\"background:#f8f9fa;border-left:3px solid var(--accent);font-size:13px\">&#128209; <b>Thuộc phần lý thuyết:</b> Giới từ chỉ SỰ BỔ SUNG (in addition to + danh từ/V-ing)</div><div class=\"mb-2 font-700 text-dark2\" style=\"font-size:13px\">&#128218; Giải thích chi tiết cả 4 đáp án:</div><div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\"><div style=\"font-weight:700;color:#555\">&#9642;&#65039; A. In spite of</div><div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\">mặc dù (sai nghĩa, đây không phải tương phản)</div></div><div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\"><div style=\"font-weight:700;color:#555\">&#9642;&#65039; B. Because of</div><div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\">vì (sai nghĩa nhân quả)</div></div><div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\"><div style=\"font-weight:700;color:#555\">&#9642;&#65039; C. As a result of</div><div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\">do kết quả của (sai nghĩa nhân quả)</div></div><div class=\"mb-2 p-3 rounded-xl\" style=\"background:#d4edda;border:1px solid rgba(0,0,0,.06)\"><div style=\"font-weight:700;color:#155724\">&#9989; D. In addition to</div><div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\">ngoài...ra, thêm vào đó (giới từ + V-ing 'painting') → đúng, bổ sung thêm kỹ năng thứ hai</div></div>"}, {"id": "conj_ex2_13", "type": "fill", "q": "I don't really want to go.__________________, it's too late now.", "vi": "", "opts": ["A. Therefore", "B. However", "C. Besides", "D. As"], "ans": 2, "explain_detail": "<div class=\"mb-2 p-3 rounded-xl font-700\" style=\"background:#d4edda;color:#155724\">&#9989; Đáp án đúng: C. Besides</div><div class=\"ex-card mb-3\">I don't really want to go.<b>Besides</b><b>Besides</b>, it's too late now.<br><span style=\"color:var(--accent);font-size:13px\">Tôi thực sự không muốn đi. Bên cạnh đó, giờ cũng đã quá muộn rồi.</span></div><div class=\"mb-3 p-3 rounded-xl\" style=\"background:#f8f9fa;border-left:3px solid var(--accent);font-size:13px\">&#128209; <b>Thuộc phần lý thuyết:</b> Trạng từ nối câu chỉ SỰ BỔ SUNG (besides)</div><div class=\"mb-2 font-700 text-dark2\" style=\"font-size:13px\">&#128218; Giải thích chi tiết cả 4 đáp án:</div><div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\"><div style=\"font-weight:700;color:#555\">&#9642;&#65039; A. Therefore</div><div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\">do đó (chỉ kết quả, không hợp vì câu 2 là một LÝ DO BỔ SUNG chứ không phải kết quả)</div></div><div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\"><div style=\"font-weight:700;color:#555\">&#9642;&#65039; B. However</div><div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\">tuy nhiên (chỉ tương phản, không hợp vì 2 câu cùng ủng hộ một ý không muốn đi)</div></div><div class=\"mb-2 p-3 rounded-xl\" style=\"background:#d4edda;border:1px solid rgba(0,0,0,.06)\"><div style=\"font-weight:700;color:#155724\">&#9989; C. Besides</div><div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\">bên cạnh đó, hơn nữa → đúng: thêm một lý do nữa để không đi</div></div><div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\"><div style=\"font-weight:700;color:#555\">&#9642;&#65039; D. As</div><div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\">vì, khi (không dùng làm trạng từ nối câu độc lập kiểu này)</div></div>"}, {"id": "conj_ex2_14", "type": "fill", "q": "Sarah left her umbrella at home.______________, she got soaked in the rain.", "vi": "", "opts": ["A. Because", "B. As a consequence", "C. By contrast", "D. However"], "ans": 1, "explain_detail": "<div class=\"mb-2 p-3 rounded-xl font-700\" style=\"background:#d4edda;color:#155724\">&#9989; Đáp án đúng: B. As a consequence</div><div class=\"ex-card mb-3\">Sarah left her umbrella at home.<b>As a consequence</b>____, she got soaked in the rain.<br><span style=\"color:var(--accent);font-size:13px\">Sarah để quên ô ở nhà. Vì vậy, cô ấy bị ướt sũng trong mưa.</span></div><div class=\"mb-3 p-3 rounded-xl\" style=\"background:#f8f9fa;border-left:3px solid var(--accent);font-size:13px\">&#128209; <b>Thuộc phần lý thuyết:</b> Trạng từ nối câu chỉ KẾT QUẢ (as a consequence)</div><div class=\"mb-2 font-700 text-dark2\" style=\"font-size:13px\">&#128218; Giải thích chi tiết cả 4 đáp án:</div><div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\"><div style=\"font-weight:700;color:#555\">&#9642;&#65039; A. Because</div><div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\">vì (là liên từ nối mệnh đề, không dùng làm trạng từ nối 2 câu độc lập sau dấu chấm)</div></div><div class=\"mb-2 p-3 rounded-xl\" style=\"background:#d4edda;border:1px solid rgba(0,0,0,.06)\"><div style=\"font-weight:700;color:#155724\">&#9989; B. As a consequence</div><div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\">hậu quả là, do đó → đúng: bị ướt LÀ HẬU QUẢ của việc quên ô</div></div><div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\"><div style=\"font-weight:700;color:#555\">&#9642;&#65039; C. By contrast</div><div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\">trái lại (chỉ đối lập, sai nghĩa)</div></div><div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\"><div style=\"font-weight:700;color:#555\">&#9642;&#65039; D. However</div><div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\">tuy nhiên (chỉ tương phản, không hợp quan hệ nhân-quả)</div></div>"}, {"id": "conj_ex2_15", "type": "fill", "q": "The weather was hot and sunny._____________, we decided to go to the beach.", "vi": "", "opts": ["A. However", "B. Moreover", "C. Since", "D. Therefore"], "ans": 3, "explain_detail": "<div class=\"mb-2 p-3 rounded-xl font-700\" style=\"background:#d4edda;color:#155724\">&#9989; Đáp án đúng: D. Therefore</div><div class=\"ex-card mb-3\">The weather was hot and sunny.<b>Therefore</b>___, we decided to go to the beach.<br><span style=\"color:var(--accent);font-size:13px\">Thời tiết nóng và nắng. Vì vậy, chúng tôi quyết định đi biển.</span></div><div class=\"mb-3 p-3 rounded-xl\" style=\"background:#f8f9fa;border-left:3px solid var(--accent);font-size:13px\">&#128209; <b>Thuộc phần lý thuyết:</b> Trạng từ nối câu chỉ KẾT QUẢ (therefore)</div><div class=\"mb-2 font-700 text-dark2\" style=\"font-size:13px\">&#128218; Giải thích chi tiết cả 4 đáp án:</div><div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\"><div style=\"font-weight:700;color:#555\">&#9642;&#65039; A. However</div><div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\">tuy nhiên (chỉ tương phản, không hợp vì câu 2 là KẾT QUẢ hợp lý của câu 1)</div></div><div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\"><div style=\"font-weight:700;color:#555\">&#9642;&#65039; B. Moreover</div><div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\">hơn nữa (chỉ bổ sung, không hợp quan hệ nhân-quả)</div></div><div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\"><div style=\"font-weight:700;color:#555\">&#9642;&#65039; C. Since</div><div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\">vì (là liên từ nối mệnh đề, không dùng làm trạng từ nối 2 câu độc lập kiểu này)</div></div><div class=\"mb-2 p-3 rounded-xl\" style=\"background:#d4edda;border:1px solid rgba(0,0,0,.06)\"><div style=\"font-weight:700;color:#155724\">&#9989; D. Therefore</div><div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\">do đó, vì vậy → đúng: đi biển LÀ KẾT QUẢ của thời tiết đẹp</div></div>"}, {"id": "conj_ex2_16", "type": "fill", "q": "I had some free time, _______ I decided to catch up on my reading.", "vi": "", "opts": ["A. yet", "B. or", "C. nor", "D. so"], "ans": 3, "explain_detail": "<div class=\"mb-2 p-3 rounded-xl font-700\" style=\"background:#d4edda;color:#155724\">&#9989; Đáp án đúng: D. so</div><div class=\"ex-card mb-3\">I had some free time, <b>so</b> I decided to catch up on my reading.<br><span style=\"color:var(--accent);font-size:13px\">Tôi có chút thời gian rảnh, vì vậy tôi quyết định đọc sách cho kịp tiến độ.</span></div><div class=\"mb-3 p-3 rounded-xl\" style=\"background:#f8f9fa;border-left:3px solid var(--accent);font-size:13px\">&#128209; <b>Thuộc phần lý thuyết:</b> Liên từ kết hợp chỉ KẾT QUẢ (so)</div><div class=\"mb-2 font-700 text-dark2\" style=\"font-size:13px\">&#128218; Giải thích chi tiết cả 4 đáp án:</div><div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\"><div style=\"font-weight:700;color:#555\">&#9642;&#65039; A. yet</div><div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\">vậy mà (chỉ tương phản, sai nghĩa)</div></div><div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\"><div style=\"font-weight:700;color:#555\">&#9642;&#65039; B. or</div><div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\">hoặc là (chỉ lựa chọn, sai nghĩa)</div></div><div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\"><div style=\"font-weight:700;color:#555\">&#9642;&#65039; C. nor</div><div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\">cũng không (dùng trong câu phủ định song song, sai nghĩa và cấu trúc)</div></div><div class=\"mb-2 p-3 rounded-xl\" style=\"background:#d4edda;border:1px solid rgba(0,0,0,.06)\"><div style=\"font-weight:700;color:#155724\">&#9989; D. so</div><div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\">vì vậy → đúng: đọc sách LÀ KẾT QUẢ của việc có thời gian rảnh</div></div>"}, {"id": "conj_ex2_17", "type": "fill", "q": "The movie received mixed reviews, _________ I found it quite enjoyable.", "vi": "", "opts": ["A. and", "B. for", "C. but", "D. or"], "ans": 2, "explain_detail": "<div class=\"mb-2 p-3 rounded-xl font-700\" style=\"background:#d4edda;color:#155724\">&#9989; Đáp án đúng: C. but</div><div class=\"ex-card mb-3\">The movie received mixed reviews, <b>but</b> I found it quite enjoyable.<br><span style=\"color:var(--accent);font-size:13px\">Bộ phim nhận được đánh giá trái chiều, nhưng tôi thấy nó khá thú vị.</span></div><div class=\"mb-3 p-3 rounded-xl\" style=\"background:#f8f9fa;border-left:3px solid var(--accent);font-size:13px\">&#128209; <b>Thuộc phần lý thuyết:</b> Liên từ kết hợp chỉ SỰ TƯƠNG PHẢN (but)</div><div class=\"mb-2 font-700 text-dark2\" style=\"font-size:13px\">&#128218; Giải thích chi tiết cả 4 đáp án:</div><div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\"><div style=\"font-weight:700;color:#555\">&#9642;&#65039; A. and</div><div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\">và (chỉ liệt kê cùng chiều, không hợp ý đối lập)</div></div><div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\"><div style=\"font-weight:700;color:#555\">&#9642;&#65039; B. for</div><div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\">vì (chỉ nguyên nhân, sai nghĩa)</div></div><div class=\"mb-2 p-3 rounded-xl\" style=\"background:#d4edda;border:1px solid rgba(0,0,0,.06)\"><div style=\"font-weight:700;color:#155724\">&#9989; C. but</div><div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\">nhưng → đúng: ý kiến cá nhân TRÁI NGƯỢC với đánh giá chung</div></div><div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\"><div style=\"font-weight:700;color:#555\">&#9642;&#65039; D. or</div><div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\">hoặc là (chỉ lựa chọn, sai nghĩa)</div></div>"}, {"id": "conj_ex2_18", "type": "fill", "q": "The music was _______ loud that it could be heard from several blocks away.", "vi": "", "opts": ["A. so", "B. such", "C. too", "D. enough"], "ans": 0, "explain_detail": "<div class=\"mb-2 p-3 rounded-xl font-700\" style=\"background:#d4edda;color:#155724\">&#9989; Đáp án đúng: A. so</div><div class=\"ex-card mb-3\">The music was <b>so</b> loud that it could be heard from several blocks away.<br><span style=\"color:var(--accent);font-size:13px\">Nhạc lớn đến mức có thể nghe thấy từ cách đó vài dãy nhà.</span></div><div class=\"mb-3 p-3 rounded-xl\" style=\"background:#f8f9fa;border-left:3px solid var(--accent);font-size:13px\">&#128209; <b>Thuộc phần lý thuyết:</b> Cấu trúc tương quan SO + adj/adv + THAT (đến mức, đến nỗi)</div><div class=\"mb-2 font-700 text-dark2\" style=\"font-size:13px\">&#128218; Giải thích chi tiết cả 4 đáp án:</div><div class=\"mb-2 p-3 rounded-xl\" style=\"background:#d4edda;border:1px solid rgba(0,0,0,.06)\"><div style=\"font-weight:700;color:#155724\">&#9989; A. so</div><div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\">đến mức (SO + tính từ 'loud' + THAT) → đúng, vì theo sau là TÍNH TỪ trực tiếp</div></div><div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\"><div style=\"font-weight:700;color:#555\">&#9642;&#65039; B. such</div><div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\">đến mức (SUCH + a/an + adj + N + THAT, cần có danh từ đi kèm, ở đây không có danh từ) → sai cấu trúc</div></div><div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\"><div style=\"font-weight:700;color:#555\">&#9642;&#65039; C. too</div><div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\">quá (TOO + adj + TO-V, không đi với THAT) → sai cấu trúc</div></div><div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\"><div style=\"font-weight:700;color:#555\">&#9642;&#65039; D. enough</div><div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\">đủ (adj + ENOUGH + TO-V, không đi với THAT) → sai cấu trúc</div></div>"}, {"id": "conj_ex2_19", "type": "fill", "q": "It was ________ a beautiful day that we decided to have a picnic in the park.", "vi": "", "opts": ["A. so", "B. such", "C. too", "D. enough"], "ans": 1, "explain_detail": "<div class=\"mb-2 p-3 rounded-xl font-700\" style=\"background:#d4edda;color:#155724\">&#9989; Đáp án đúng: B. such</div><div class=\"ex-card mb-3\">It was <b>such</b> a beautiful day that we decided to have a picnic in the park.<br><span style=\"color:var(--accent);font-size:13px\">Đó là một ngày đẹp trời đến mức chúng tôi quyết định đi dã ngoại ở công viên.</span></div><div class=\"mb-3 p-3 rounded-xl\" style=\"background:#f8f9fa;border-left:3px solid var(--accent);font-size:13px\">&#128209; <b>Thuộc phần lý thuyết:</b> Cấu trúc tương quan SUCH + a/an + adj + N + THAT (đến mức)</div><div class=\"mb-2 font-700 text-dark2\" style=\"font-size:13px\">&#128218; Giải thích chi tiết cả 4 đáp án:</div><div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\"><div style=\"font-weight:700;color:#555\">&#9642;&#65039; A. so</div><div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\">đến mức (SO + adj, không đi trực tiếp với 'a beautiful day' vì có mạo từ + danh từ) → sai cấu trúc</div></div><div class=\"mb-2 p-3 rounded-xl\" style=\"background:#d4edda;border:1px solid rgba(0,0,0,.06)\"><div style=\"font-weight:700;color:#155724\">&#9989; B. such</div><div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\">đến mức (SUCH + a + beautiful day + THAT) → đúng, vì có mạo từ 'a' và danh từ 'day' đi kèm</div></div><div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\"><div style=\"font-weight:700;color:#555\">&#9642;&#65039; C. too</div><div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\">quá (không đi với THAT) → sai cấu trúc</div></div><div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\"><div style=\"font-weight:700;color:#555\">&#9642;&#65039; D. enough</div><div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\">đủ (không đi với THAT theo cách này) → sai cấu trúc</div></div>"}, {"id": "conj_ex2_20", "type": "fill", "q": "The problem was _________ complex for me to solve on my own.", "vi": "", "opts": ["A. so", "B. such", "C. too", "D. enough"], "ans": 2, "explain_detail": "<div class=\"mb-2 p-3 rounded-xl font-700\" style=\"background:#d4edda;color:#155724\">&#9989; Đáp án đúng: C. too</div><div class=\"ex-card mb-3\">The problem was <b>too</b> complex for me to solve on my own.<br><span style=\"color:var(--accent);font-size:13px\">Vấn đề quá phức tạp để tôi có thể tự giải quyết một mình.</span></div><div class=\"mb-3 p-3 rounded-xl\" style=\"background:#f8f9fa;border-left:3px solid var(--accent);font-size:13px\">&#128209; <b>Thuộc phần lý thuyết:</b> Cấu trúc TOO + adj + (FOR sb) + TO-V (quá... để...)</div><div class=\"mb-2 font-700 text-dark2\" style=\"font-size:13px\">&#128218; Giải thích chi tiết cả 4 đáp án:</div><div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\"><div style=\"font-weight:700;color:#555\">&#9642;&#65039; A. so</div><div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\">đến mức (SO...THAT, không đi với TO-V kiểu này) → sai cấu trúc</div></div><div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\"><div style=\"font-weight:700;color:#555\">&#9642;&#65039; B. such</div><div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\">đến mức (SUCH...THAT, không đi với TO-V) → sai cấu trúc</div></div><div class=\"mb-2 p-3 rounded-xl\" style=\"background:#d4edda;border:1px solid rgba(0,0,0,.06)\"><div style=\"font-weight:700;color:#155724\">&#9989; C. too</div><div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\">quá (TOO + complex + for me + to solve) → đúng, đúng cấu trúc TOO...TO</div></div><div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\"><div style=\"font-weight:700;color:#555\">&#9642;&#65039; D. enough</div><div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\">đủ (ENOUGH đứng SAU tính từ: complex enough, ở đây đứng trước sai vị trí) → sai cấu trúc</div></div>"}, {"id": "conj_ex2_21", "type": "fill", "q": "____had Rina finished her homework when the electricity went out.", "vi": "", "opts": ["A. Before", "B. After", "C. No sooner", "D. Hardly"], "ans": 3, "explain_detail": "<div class=\"mb-2 p-3 rounded-xl font-700\" style=\"background:#d4edda;color:#155724\">&#9989; Đáp án đúng: D. Hardly</div><div class=\"ex-card mb-3\">____had Rina finished her homework when the electricity went out.<br><span style=\"color:var(--accent);font-size:13px\">Rina vừa mới làm xong bài tập thì mất điện.</span></div><div class=\"mb-3 p-3 rounded-xl\" style=\"background:#f8f9fa;border-left:3px solid var(--accent);font-size:13px\">&#128209; <b>Thuộc phần lý thuyết:</b> Cấu trúc đảo ngữ HARDLY...WHEN (vừa mới... thì đã...)</div><div class=\"mb-2 font-700 text-dark2\" style=\"font-size:13px\">&#128218; Giải thích chi tiết cả 4 đáp án:</div><div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\"><div style=\"font-weight:700;color:#555\">&#9642;&#65039; A. Before</div><div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\">trước khi (không tạo cặp đảo ngữ này)</div></div><div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\"><div style=\"font-weight:700;color:#555\">&#9642;&#65039; B. After</div><div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\">sau khi (không tạo cặp đảo ngữ này)</div></div><div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\"><div style=\"font-weight:700;color:#555\">&#9642;&#65039; C. No sooner</div><div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\">vừa mới (đi với THAN chứ không phải WHEN) → sai vì câu có 'when'</div></div><div class=\"mb-2 p-3 rounded-xl\" style=\"background:#d4edda;border:1px solid rgba(0,0,0,.06)\"><div style=\"font-weight:700;color:#155724\">&#9989; D. Hardly</div><div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\">vừa mới... thì đã... (đi với 'when', đảo ngữ 'had Rina finished') → đúng</div></div>"}, {"id": "conj_ex2_22", "type": "fill", "q": "They were ______ sad nor disappointed with their exam results.", "vi": "", "opts": ["A. neither", "B. either", "C. not only", "D. whether"], "ans": 0, "explain_detail": "<div class=\"mb-2 p-3 rounded-xl font-700\" style=\"background:#d4edda;color:#155724\">&#9989; Đáp án đúng: A. neither</div><div class=\"ex-card mb-3\">They were <b>neither</b> sad nor disappointed with their exam results.<br><span style=\"color:var(--accent);font-size:13px\">Họ không buồn cũng không thất vọng về kết quả thi của mình.</span></div><div class=\"mb-3 p-3 rounded-xl\" style=\"background:#f8f9fa;border-left:3px solid var(--accent);font-size:13px\">&#128209; <b>Thuộc phần lý thuyết:</b> Liên từ tương quan NEITHER...NOR (không... cũng không...)</div><div class=\"mb-2 font-700 text-dark2\" style=\"font-size:13px\">&#128218; Giải thích chi tiết cả 4 đáp án:</div><div class=\"mb-2 p-3 rounded-xl\" style=\"background:#d4edda;border:1px solid rgba(0,0,0,.06)\"><div style=\"font-weight:700;color:#155724\">&#9989; A. neither</div><div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\">không... (đi với 'nor' có sẵn) → đúng</div></div><div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\"><div style=\"font-weight:700;color:#555\">&#9642;&#65039; B. either</div><div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\">hoặc (đi với 'or', không khớp với 'nor')</div></div><div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\"><div style=\"font-weight:700;color:#555\">&#9642;&#65039; C. not only</div><div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\">không những (đi với 'but also', không khớp với 'nor')</div></div><div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\"><div style=\"font-weight:700;color:#555\">&#9642;&#65039; D. whether</div><div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\">liệu có... hay không (đi với 'or', không khớp với 'nor')</div></div>"}, {"id": "conj_ex2_23", "type": "fill", "q": "She played _____ hockey ____ basketball when she was a student.", "vi": "", "opts": ["A. so- that", "B. no sooner- than", "C. both- and", "D. such- that"], "ans": 2, "explain_detail": "<div class=\"mb-2 p-3 rounded-xl font-700\" style=\"background:#d4edda;color:#155724\">&#9989; Đáp án đúng: C. both- and</div><div class=\"ex-card mb-3\">She played <b>both- and</b> hockey ____ basketball when she was a student.<br><span style=\"color:var(--accent);font-size:13px\">Cô ấy chơi cả khúc côn cầu lẫn bóng rổ khi còn là học sinh.</span></div><div class=\"mb-3 p-3 rounded-xl\" style=\"background:#f8f9fa;border-left:3px solid var(--accent);font-size:13px\">&#128209; <b>Thuộc phần lý thuyết:</b> Liên từ tương quan BOTH...AND (vừa... vừa..., cả... và...)</div><div class=\"mb-2 font-700 text-dark2\" style=\"font-size:13px\">&#128218; Giải thích chi tiết cả 4 đáp án:</div><div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\"><div style=\"font-weight:700;color:#555\">&#9642;&#65039; A. so- that</div><div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\">đến mức (không hợp ngữ cảnh liệt kê 2 môn thể thao)</div></div><div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\"><div style=\"font-weight:700;color:#555\">&#9642;&#65039; B. no sooner- than</div><div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\">vừa mới... thì đã... (không hợp nghĩa liệt kê)</div></div><div class=\"mb-2 p-3 rounded-xl\" style=\"background:#d4edda;border:1px solid rgba(0,0,0,.06)\"><div style=\"font-weight:700;color:#155724\">&#9989; C. both- and</div><div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\">cả... và... → đúng: cô ấy chơi CẢ HAI môn thể thao</div></div><div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\"><div style=\"font-weight:700;color:#555\">&#9642;&#65039; D. such- that</div><div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\">đến mức (không hợp ngữ cảnh liệt kê)</div></div>"}, {"id": "conj_ex2_24", "type": "fill", "q": "I was tired after my journey, _____ I had been forced to bike 20 miles.", "vi": "", "opts": ["A. unless", "B. so", "C. but", "D. for"], "ans": 3, "explain_detail": "<div class=\"mb-2 p-3 rounded-xl font-700\" style=\"background:#d4edda;color:#155724\">&#9989; Đáp án đúng: D. for</div><div class=\"ex-card mb-3\">I was tired after my journey, <b>for</b> I had been forced to bike 20 miles.<br><span style=\"color:var(--accent);font-size:13px\">Tôi mệt sau chuyến đi, vì tôi đã phải đạp xe 20 dặm.</span></div><div class=\"mb-3 p-3 rounded-xl\" style=\"background:#f8f9fa;border-left:3px solid var(--accent);font-size:13px\">&#128209; <b>Thuộc phần lý thuyết:</b> Liên từ kết hợp chỉ NGUYÊN NHÂN (for = vì, trang trọng)</div><div class=\"mb-2 font-700 text-dark2\" style=\"font-size:13px\">&#128218; Giải thích chi tiết cả 4 đáp án:</div><div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\"><div style=\"font-weight:700;color:#555\">&#9642;&#65039; A. unless</div><div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\">trừ khi (chỉ điều kiện, sai nghĩa)</div></div><div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\"><div style=\"font-weight:700;color:#555\">&#9642;&#65039; B. so</div><div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\">vì vậy (chỉ kết quả, sai chiều quan hệ — đây mệt LÀ KẾT QUẢ của vế sau chứ không phải nguyên nhân)</div></div><div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\"><div style=\"font-weight:700;color:#555\">&#9642;&#65039; C. but</div><div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\">nhưng (chỉ tương phản, sai nghĩa)</div></div><div class=\"mb-2 p-3 rounded-xl\" style=\"background:#d4edda;border:1px solid rgba(0,0,0,.06)\"><div style=\"font-weight:700;color:#155724\">&#9989; D. for</div><div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\">vì (liên từ kết hợp trang trọng, giải thích lý do mệt) → đúng</div></div>"}, {"id": "conj_ex2_25", "type": "fill", "q": "My husband only likes classical music – I, ________, like all kinds.", "vi": "", "opts": ["A. on the other hand", "B. on the condition that", "C. on the whole", "D. on the way"], "ans": 0, "explain_detail": "<div class=\"mb-2 p-3 rounded-xl font-700\" style=\"background:#d4edda;color:#155724\">&#9989; Đáp án đúng: A. on the other hand</div><div class=\"ex-card mb-3\">My husband only likes classical music – I, <b>on the other hand</b>, like all kinds.<br><span style=\"color:var(--accent);font-size:13px\">Chồng tôi chỉ thích nhạc cổ điển – còn tôi thì ngược lại, thích đủ mọi thể loại.</span></div><div class=\"mb-3 p-3 rounded-xl\" style=\"background:#f8f9fa;border-left:3px solid var(--accent);font-size:13px\">&#128209; <b>Thuộc phần lý thuyết:</b> Trạng từ nối câu chỉ SỰ ĐỐI LẬP (on the other hand = mặt khác)</div><div class=\"mb-2 font-700 text-dark2\" style=\"font-size:13px\">&#128218; Giải thích chi tiết cả 4 đáp án:</div><div class=\"mb-2 p-3 rounded-xl\" style=\"background:#d4edda;border:1px solid rgba(0,0,0,.06)\"><div style=\"font-weight:700;color:#155724\">&#9989; A. on the other hand</div><div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\">mặt khác → đúng: đối lập sở thích của 2 người</div></div><div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\"><div style=\"font-weight:700;color:#555\">&#9642;&#65039; B. on the condition that</div><div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\">với điều kiện là (sai nghĩa)</div></div><div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\"><div style=\"font-weight:700;color:#555\">&#9642;&#65039; C. on the whole</div><div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\">nhìn chung (sai nghĩa)</div></div><div class=\"mb-2 p-3 rounded-xl\" style=\"background:#f8f9fa;border:1px solid rgba(0,0,0,.06)\"><div style=\"font-weight:700;color:#555\">&#9642;&#65039; D. on the way</div><div class=\"mt-1\" style=\"font-size:12px;color:var(--text-soft)\">trên đường đi (sai nghĩa hoàn toàn)</div></div>"}];
